import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard } from '../types';

const Accounts: React.FC = () => {
  const { filteredState, state } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Individual';
  };

  const calculateAnnualSpend = (card: CreditCard) => {
    if (!card.annualLimit || !card.anniversaryDate) return 0;

    const now = new Date();
    const anniv = new Date(card.anniversaryDate);

    // Determine the start of the current annual cycle
    let cycleStart = new Date(now.getFullYear(), anniv.getMonth(), anniv.getDate());
    if (cycleStart > now) {
      cycleStart.setFullYear(cycleStart.getFullYear() - 1);
    }

    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const calculateCycleDues = (card: CreditCard) => {
    if (!card.billingDay) return card.balance;

    const now = new Date();
    let cycleStart = new Date(now.getFullYear(), now.getMonth(), card.billingDay);
    if (cycleStart > now) {
      cycleStart.setMonth(cycleStart.getMonth() - 1);
    }

    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  return (
    <div className="space-y-12 animate-in fade-in duration-500">
      {/* Depository Section */}
      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Depository Accounts</h3>
            <p className="text-xs text-slate-400 font-medium">Bank balances and savings</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('bank'); }}
            className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-200"
          >
            + Add Bank
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-white p-6 rounded-2xl border border-slate-200 relative group hover:shadow-xl transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[10px] font-bold uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-2xl">🏦</div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-xl font-black text-slate-800 tracking-tight">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{bank.name}</h4>
                 <p className="text-xs font-medium text-indigo-500 mt-1 uppercase tracking-widest">
                    {bank.accountType === 'Others' ? bank.customAccountType : bank.accountType}
                 </p>
              </div>
              <p className="text-xs font-mono text-slate-400">{bank.accountNumber || '**** **** ****'}</p>
              <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition-all pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('bank', bank)} className="text-[10px] font-bold uppercase text-indigo-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[10px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Wallets Section */}
      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Digital & Cash Wallets</h3>
            <p className="text-xs text-slate-400 font-medium">On-hand liquidity and apps</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('wallet'); }}
            className="px-5 py-2.5 bg-emerald-600 text-white rounded-xl text-xs font-bold hover:bg-emerald-700 transition-all shadow-md shadow-emerald-200"
          >
            + Add Wallet
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {(filteredState.wallets || []).map(wallet => (
            <div key={wallet.id} className="bg-white p-6 rounded-2xl border border-slate-200 relative group hover:shadow-xl transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[10px] font-bold uppercase text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{getOwnerName(wallet.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-12 h-12 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center text-2xl">👛</div>
                <div className="text-right">
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-xl font-black text-slate-800 tracking-tight">{formatCurrency(wallet.balance, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{wallet.name}</h4>
                 <p className="text-[10px] font-bold text-emerald-500 mt-1 uppercase tracking-widest">Liquid Cash</p>
              </div>
              <div className="flex gap-4 opacity-0 group-hover:opacity-100 transition-all pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('wallet', wallet)} className="text-[10px] font-bold uppercase text-emerald-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(wallet)} className="text-[10px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Credit Section */}
      <section>
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Credit Lines</h3>
            <p className="text-xs text-slate-400 font-medium">Outstanding cards and limit tracking</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('card'); }}
            className="px-5 py-2.5 bg-slate-800 text-white rounded-xl text-xs font-bold hover:bg-slate-900 transition-all shadow-md shadow-slate-200"
          >
            + New Card
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          {(filteredState.cards || []).map(card => {
            const annualUsed = calculateAnnualSpend(card);
            const cycleDues = calculateCycleDues(card);
            const annualLimit = card.annualLimit || 0;
            const spendPercentage = annualLimit > 0 ? (annualUsed / annualLimit) * 100 : 0;

            return (
              <div key={card.id} className="relative overflow-hidden bg-gradient-to-br from-indigo-600 to-indigo-800 p-8 rounded-3xl text-white shadow-xl shadow-indigo-100 group flex flex-col justify-between min-h-[320px]">
                <span className="absolute top-6 right-6 text-[10px] font-bold uppercase text-white/40 tracking-widest">{getOwnerName(card.ownerId)}</span>
                <div className="relative z-10">
                  <div className="flex justify-between items-start mb-8">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <p className="text-[10px] text-indigo-200 font-bold uppercase tracking-widest">Total Outstanding</p>
                        <span className="text-[9px] bg-white/20 px-1.5 py-0.5 rounded text-white font-black">P&L View</span>
                      </div>
                      <p className="text-3xl font-black tracking-tight">{formatCurrency(card.balance, currency)}</p>

                      <div className="mt-4 flex items-center gap-2">
                        <p className="text-[10px] text-indigo-200 font-bold uppercase tracking-widest">Cycle Dues</p>
                        <p className="text-lg font-black">{formatCurrency(cycleDues, currency)}</p>
                      </div>
                    </div>
                    <div className="text-right">
                      <p className="text-sm font-bold border-b border-white/20 pb-1 mb-2">{card.lenderName}</p>
                      <div className="flex gap-2 justify-end">
                        <span className={`p-1 rounded ${card.offers.movie ? 'bg-white/20' : 'opacity-20 grayscale'}`} title="Movies">🎬</span>
                        <span className={`p-1 rounded ${card.offers.dining ? 'bg-white/20' : 'opacity-20 grayscale'}`} title="Dining">🍽️</span>
                        <span className={`p-1 rounded ${card.offers.concierge ? 'bg-white/20' : 'opacity-20 grayscale'}`} title="Concierge">🎩</span>
                        <span className={`p-1 rounded ${card.offers.lounge ? 'bg-white/20' : 'opacity-20 grayscale'}`} title="Lounge">🛋️</span>
                      </div>
                    </div>
                  </div>

                  {annualLimit > 0 && (
                    <div className="mb-8 space-y-3 bg-white/10 p-5 rounded-2xl backdrop-blur-sm border border-white/10">
                      <div className="flex justify-between items-center">
                        <p className="text-[10px] font-bold uppercase text-indigo-100">Annual Limit Status</p>
                        <p className="text-xs font-black">{Math.round(spendPercentage)}%</p>
                      </div>
                      <div className="w-full h-1.5 bg-black/10 rounded-full overflow-hidden">
                        <div 
                          className={`h-full transition-all duration-1000 ${spendPercentage > 90 ? 'bg-rose-400' : 'bg-white'}`} 
                          style={{ width: `${Math.min(100, spendPercentage)}%` }} 
                        />
                      </div>
                      <div className="flex justify-between items-center text-[10px] font-bold text-indigo-100/60 uppercase">
                        <span>Used: {formatCurrency(annualUsed, currency)}</span>
                        <span>Goal: {formatCurrency(annualLimit, currency)}</span>
                      </div>
                    </div>
                  )}
                </div>

                <div className="relative z-10 flex justify-between items-end border-t border-white/10 pt-6">
                  <p className="text-sm font-mono tracking-widest text-indigo-100">•••• •••• •••• {card.last4}</p>
                  <div className="flex gap-4">
                    <button onClick={() => handleEdit('card', card)} className="text-[10px] font-bold uppercase text-indigo-200 hover:text-white transition-colors">Edit</button>
                    <button onClick={() => setViewingHistory(card)} className="text-[10px] font-bold uppercase text-indigo-200 hover:text-white transition-colors">History</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-2xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200 my-8">
            <h3 className="text-lg font-bold text-slate-800 mb-6 pb-4 border-b border-slate-100">Configure {showModal?.charAt(0).toUpperCase() + showModal?.slice(1)}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}

      {viewingHistory && (
        <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />
      )}
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: account.balance,
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    anniversaryDate: account.anniversaryDate || '',
    billingDay: account.billingDay || 1,
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    name: '',
    balance: '',
    accNum: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    anniversaryDate: '',
    billingDay: 1,
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });

  const familyMembers = state.profile?.familyMembers || [];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };

    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const cardData = { 
        ...commonProps, 
        lenderName: formData.name, 
        balance: Number(formData.balance), 
        last4: formData.last4, 
        limit: formData.limit ? Number(formData.limit) : undefined, 
        annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, 
        anniversaryDate: formData.anniversaryDate,
        billingDay: Number(formData.billingDay),
        offers: formData.offers 
      };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="space-y-1">
        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Owner</label>
        <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}>
          <option value="">Self (Individual)</option>
          {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
        </select>
      </div>

      <div className="grid grid-cols-2 gap-4">
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">
            {type === 'card' ? 'Lender Name' : (type === 'wallet' ? 'Wallet Name' : 'Entity Name')}
          </label>
          <input 
            required 
            placeholder={type === 'card' ? 'e.g. HDFC, Amex' : (type === 'wallet' ? 'e.g. Cash, Paytm' : 'e.g. Chase')} 
            className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" 
            value={formData.name} 
            onChange={e => setFormData({...formData, name: e.target.value})} 
          />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Opening Balance</label>
          <input required type="number" step="any" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-lg" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} />
        </div>
      </div>

      {type === 'card' && (
        <>
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Card ending with (Last 4)</label>
              <input required maxLength={4} placeholder="1234" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-sm" value={formData.last4} onChange={e => setFormData({...formData, last4: e.target.value.replace(/\D/g, '')})} />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Billing Day (1-31)</label>
              <input type="number" min={1} max={31} className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.billingDay} onChange={e => setFormData({...formData, billingDay: e.target.value})} />
            </div>
          </div>

          <div className="space-y-4 p-4 bg-slate-50 rounded-xl border border-slate-200">
             <div className="flex justify-between items-center">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Offers Applicable</label>
                <p className="text-[9px] text-indigo-500 font-medium italic">Don't know? <button type="button" className="underline font-bold" onClick={() => alert("Support ticket raised. We will add benefits shortly.")}>Raise Ticket</button></p>
             </div>
             <div className="grid grid-cols-2 gap-4">
               {[
                 { key: 'movie', label: 'Movie tickets', icon: '🎬' },
                 { key: 'dining', label: 'Dining offers', icon: '🍽️' },
                 { key: 'concierge', label: 'Concierge', icon: '🎩' },
                 { key: 'lounge', label: 'Lounge access', icon: '🛋️' }
               ].map(off => (
                 <label key={off.key} className="flex items-center gap-2 cursor-pointer group">
                    <input type="checkbox" className="w-4 h-4 rounded border-slate-300 text-indigo-600 focus:ring-indigo-500" checked={formData.offers[off.key]} onChange={e => setFormData({...formData, offers: { ...formData.offers, [off.key]: e.target.checked }})} />
                    <span className="text-xs font-medium text-slate-600 group-hover:text-slate-900 transition-colors">{off.icon} {off.label}</span>
                 </label>
               ))}
             </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Annual Spend Limit</label>
              <input type="number" placeholder="Optional" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.annualLimit} onChange={e => setFormData({...formData, annualLimit: e.target.value})} />
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Cycle Anniversary Date</label>
              <input type="date" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-xs" value={formData.anniversaryDate} onChange={e => setFormData({...formData, anniversaryDate: e.target.value})} />
            </div>
          </div>
        </>
      )}

      {type === 'bank' && (
        <div className="space-y-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Account Number</label>
          <input placeholder="Last 4 or Full Number" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-mono text-sm" value={formData.accNum} onChange={e => setFormData({...formData, accNum: e.target.value})} />
        </div>
      )}

      <div className="flex gap-4 pt-6">
        <button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-xs">Discard</button>
        <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-indigo-100">Save {type === 'wallet' ? 'Wallet' : 'Asset'}</button>
      </div>
    </form>
  );
};

const TransactionHistoryModal: React.FC<{ account: any, currency: string, onClose: () => void }> = ({ account, currency, onClose }) => {
  const { filteredState } = useFinance();
  const tenDaysAgo = new Date();
  tenDaysAgo.setDate(tenDaysAgo.getDate() - 10);
  const [dateFrom, setDateFrom] = useState(tenDaysAgo.toISOString().split('T')[0]);
  const [dateTo, setDateTo] = useState(new Date().toISOString().split('T')[0]);

  const history = useMemo(() => {
    return (filteredState.transactions || [])
      .filter(t => t.accountId === account.id)
      .filter(t => t.date >= dateFrom && t.date <= dateTo)
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [filteredState.transactions, account.id, dateFrom, dateTo]);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
      <div className="bg-white w-full max-w-3xl rounded-2xl p-8 shadow-2xl animate-in fade-in slide-in-from-bottom-8 duration-300 max-h-[90vh] flex flex-col">
        <div className="flex justify-between items-start mb-8 border-b border-slate-100 pb-4">
          <div>
            <h3 className="text-lg font-bold text-slate-800">{account.name || account.lenderName} Ledger</h3>
            <p className="text-xs font-medium text-indigo-500 uppercase tracking-widest mt-1">Audit Trail</p>
          </div>
          <button onClick={onClose} className="p-2 text-slate-300 hover:text-slate-600 transition-all text-xl">✕</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8 bg-slate-50 p-6 rounded-2xl border border-slate-100">
          <div>
             <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1 ml-1">From</label>
             <input type="date" className="w-full bg-white border border-slate-200 rounded-xl p-2.5 text-xs font-bold" value={dateFrom} onChange={e => setDateFrom(e.target.value)} />
          </div>
          <div>
             <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1 ml-1">To</label>
             <input type="date" className="w-full bg-white border border-slate-200 rounded-xl p-2.5 text-xs font-bold" value={dateTo} onChange={e => setDateTo(e.target.value)} />
          </div>
          <div className="text-right flex flex-col justify-center">
             <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Net Flow</p>
             <p className={`text-xl font-black ${history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0) >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                {formatCurrency(history.reduce((acc, t) => acc + (t.type === 'Income' ? t.amount : -t.amount), 0), currency)}
             </p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 space-y-3">
          {history.length > 0 ? (
            history.map(t => (
              <div key={t.id} className="p-4 bg-white border border-slate-100 rounded-xl flex items-center justify-between hover:border-indigo-100 transition-all">
                 <div className="flex items-center gap-4">
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-sm font-bold shadow-sm ${t.type === 'Income' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>
                      {t.type === 'Income' ? '↑' : '↓'}
                    </div>
                    <div>
                      <p className="text-sm font-bold text-slate-800">{t.description}</p>
                      <p className="text-[10px] font-medium text-slate-400">{t.date} • {t.category || 'General'}</p>
                    </div>
                 </div>
                 <p className={`text-sm font-black ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                   {t.type === 'Income' ? '+' : '-'}{formatCurrency(t.amount, currency)}
                 </p>
              </div>
            ))
          ) : (
            <div className="text-center py-20 opacity-30 text-slate-400 text-sm italic">No entries in range</div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Accounts;

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => void;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => void;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [
    { id: 'default-cash', name: 'Cash', balance: 0 }
  ],
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  // Persist local state whenever it changes, keyed by mobile number
  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  // Cloud Sync Logic
  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', mobile)
        .single();

      if (data && data.state) {
        // Strict isolation: When loading from cloud, we replace current state
        setState(data.state);
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({
        ...initialState,
        ...newState,
        profile: { ...initialState.profile, ...newState.profile }
      });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = (member: FamilyMember) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }] }
  }));

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => 
        m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m
      )
    }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ ...prev, banks: [...(prev.banks || []), bank] }));
  const updateBank = (bank: BankAccount) => setState(prev => ({ ...prev, banks: (prev.banks || []).map(b => b.id === bank.id ? bank : b) }));
  const deleteBank = (id: string) => setState(prev => ({ ...prev, banks: (prev.banks || []).filter(b => b.id !== id) }));

  const addCard = (card: CreditCard) => setState(prev => ({ ...prev, cards: [...(prev.cards || []), card] }));
  const updateCard = (card: CreditCard) => setState(prev => ({ ...prev, cards: (prev.cards || []).map(c => c.id === card.id ? card : c) }));
  const deleteCard = (id: string) => setState(prev => ({ ...prev, cards: (prev.cards || []).filter(c => c.id !== id) }));

  const addWallet = (wallet: Wallet) => setState(prev => ({ ...prev, wallets: [...(prev.wallets || []), wallet] }));
  const updateWallet = (wallet: Wallet) => setState(prev => ({ ...prev, wallets: (prev.wallets || []).map(w => w.id === wallet.id ? wallet : w) }));
  const deleteWallet = (id: string) => setState(prev => ({ ...prev, wallets: (prev.wallets || []).filter(w => w.id !== id) }));

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...(prev.incomes || []), income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...(prev.expenses || []), expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...(prev.assets || []), asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...(prev.liabilities || []), liability] }));

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const amount = transaction.amount;
    const delta = (transaction.type === 'Income' || transaction.type === 'Liability') ? amount : -amount;
    const finalDelta = delta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const sharedAmt = transaction.sharedAmount || 0;
      const selfAmt = transaction.amount - sharedAmt;

      switch (transaction.type) {
        case 'Income':
          if (selfAmt > 0) newState.incomes.push({ id: transaction.id, name: transaction.description, amount: selfAmt, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Expense':
          if (selfAmt > 0) newState.expenses.push({ id: transaction.id, category: transaction.category || 'Others', amount: selfAmt, date: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: transaction.description, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: transaction.description, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    const writableMembers = state.profile.familyMembers.filter(m => m.canAddTransactions !== false);
    if (writableMembers.length === 0) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const familyNames = writableMembers.map(m => m.name).join(", ");
    const prompt = `Based on these family members: [${familyNames}], generate one realistic financial transaction that one of them might have recently made. Return ONLY a JSON object with: { memberName: string, amount: number, description: string, type: "Expense"|"Income", category: string }.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text);
      const member = writableMembers.find(m => m.name === data.memberName) || writableMembers[0];

      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: data.type,
        amount: data.amount,
        description: data.description,
        accountId: 'synced-external',
        accountType: 'bank',
        date: new Date().toISOString().split('T')[0],
        category: data.category,
        ownerId: member.id
      };

      const newNotification: Notification = {
        id: Math.random().toString(36).substr(2, 9),
        title: `Cloud Entry from ${member.name}`,
        message: `${data.description} was synchronized. Amount: ${state.profile.currency} ${data.amount.toLocaleString()}.`,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      };

      setState(prev => {
        const newState = { 
          ...prev, 
          transactions: [newTransaction, ...(prev.transactions || [])],
          notifications: [...(prev.notifications || []), newNotification] 
        };
        applyTransactionEffect(newTransaction, newState, false);
        return newState;
      });

    } catch (e) {}
  };

  const filteredState = useMemo(() => {
    const isFiltered = activeMemberIds.length > 0 && !activeMemberIds.includes('all');
    if (!isFiltered && activeMemberIds.includes('all')) return state;
    const filterIds = activeMemberIds.length === 0 ? [undefined, ''] : activeMemberIds;
    const filterFn = (item: any) => {
      const ownerId = item.ownerId || '';
      return filterIds.includes(ownerId) || (filterIds.includes('') && ownerId === undefined);
    };
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(fn => filterIds.includes(fn.ownerId || '')),
      wallets: (state.wallets || []).filter(fn => filterIds.includes(fn.ownerId || '')),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = () => { 
    // Clear global session but keep individual user storage intact for security
    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, addIncome, addExpense, addAsset, addLiability,
      addTransaction, updateTransaction, deleteTransaction, 
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard } from '../types';

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'bank' | 'card' | 'wallet', name: string } | null>(null);

  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Individual';
  };

  const calculateAnnualSpend = (card: CreditCard) => {
    if (!card.annualLimit || !card.anniversaryDate) return 0;

    const now = new Date();
    const anniv = new Date(card.anniversaryDate);

    // Determine the start of the current annual cycle
    let cycleStart = new Date(now.getFullYear(), anniv.getMonth(), anniv.getDate());
    if (cycleStart > now) {
      cycleStart.setFullYear(cycleStart.getFullYear() - 1);
    }

    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const calculateCycleDues = (card: CreditCard) => {
    if (!card.billingDay) return card.balance;

    const now = new Date();
    let cycleStart = new Date(now.getFullYear(), now.getMonth(), card.billingDay);
    if (cycleStart > now) {
      cycleStart.setMonth(cycleStart.getMonth() - 1);
    }

    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

