import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => void;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', mobile)
        .single();

      if (data && data.state) {
        setState(data.state);
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({
        ...initialState,
        ...newState,
        profile: { ...initialState.profile, ...newState.profile }
      });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    // 1. Prevent self-linking
    if (member.mobileNumber === state.profile.mobileNumber) {
      return { success: false, syncedCount: 0, error: "Cannot link your own account as a family member." };
    }

    // 2. Check for existing linkage
    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) {
      return { success: false, syncedCount: 0, error: 'Member already linked.' };
    }

    let syncedCount = 0;
    let memberData: any = null;

    try {
      const { data } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', member.mobileNumber)
        .single();

      if (data && data.state) {
        memberData = data.state;
      }
    } catch (err) {
      console.warn('Member vault not found for sync');
    }

    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];

      if (!memberData) {
        return {
          ...prev,
          profile: { ...prev.profile, familyMembers: newFamilyMembers }
        };
      }

      // Rename accounts to avoid confusion (e.g. John's Chase)
      const syncTag = (item: any) => {
        // Fix: If it's a "Cash" account, keep name "Cash" so it can be merged in consolidated view later
        const isCash = item.name === 'Cash' || item.id === 'default-cash';
        return { 
          ...item, 
          id: `${member.id}_${item.id}`, 
          name: isCash ? 'Cash' : (item.name ? `${member.name}'s ${item.name}` : undefined),
          lenderName: item.lenderName ? `${member.name}'s ${item.lenderName}` : undefined,
          ownerId: member.id 
        };
      };

      const syncTx = (tx: Transaction) => ({
        ...tx,
        id: `${member.id}_${tx.id}`,
        accountId: `${member.id}_${tx.accountId}`,
        ownerId: member.id
      });

      const newBanks = (memberData.banks || []).map(syncTag);
      const newCards = (memberData.cards || []).map(syncTag);
      const newWallets = (memberData.wallets || []).map(syncTag);
      const newTransactions = (memberData.transactions || []).map(syncTx);
      const newIncomes = (memberData.incomes || []).map(syncTag);
      const newExpenses = (memberData.expenses || []).map(syncTag);
      const newAssets = (memberData.assets || []).map(syncTag);
      const newLiabilities = (memberData.liabilities || []).map(syncTag);

      syncedCount = newBanks.length + newCards.length + newWallets.length + newTransactions.length;

      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...newBanks],
        cards: [...(prev.cards || []), ...newCards],
        wallets: [...(prev.wallets || []), ...newWallets],
        transactions: [...(prev.transactions || []), ...newTransactions],
        incomes: [...(prev.incomes || []), ...newIncomes],
        expenses: [...(prev.expenses || []), ...newExpenses],
        assets: [...(prev.assets || []), ...newAssets],
        liabilities: [...(prev.liabilities || []), ...newLiabilities],
        notifications: [...(prev.notifications || []), {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Family Sync Complete',
          message: `Successfully linked ${member.name} and synchronized ${syncedCount} financial records.`,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          type: 'sync',
          isRead: false
        }]
      };
    });

    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => 
        m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m
      )
    }
  }));

  const cleanAccountData = (prev: FinancialState, accountId: string) => {
    const transactionsToRemove = (prev.transactions || []).filter(t => t.accountId === accountId);
    const txIds = new Set(transactionsToRemove.map(t => t.id));

    return {
      ...prev,
      transactions: (prev.transactions || []).filter(t => t.accountId !== accountId),
      incomes: (prev.incomes || []).filter(i => !txIds.has(i.id)),
      expenses: (prev.expenses || []).filter(e => !txIds.has(e.id)),
      assets: (prev.assets || []).filter(a => !txIds.has(a.id) && !Array.from(txIds).some(tid => a.id.startsWith(tid + '_shared'))),
      liabilities: (prev.liabilities || []).filter(l => !txIds.has(l.id) && !Array.from(txIds).some(tid => l.id.startsWith(tid + '_shared')))
    };
  };

  const addBank = (bank: BankAccount) => setState(prev => {
    const exists = prev.banks.some(b => b.id === bank.id);
    if (exists) return { ...prev, banks: prev.banks.map(b => b.id === bank.id ? bank : b) };
    return { ...prev, banks: [...(prev.banks || []), bank] };
  });

  const updateBank = (bank: BankAccount) => addBank(bank);

  const deleteBank = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, banks: (next.banks || []).filter(b => b.id !== id) };
  });

  const addCard = (card: CreditCard) => setState(prev => {
    const exists = prev.cards.some(c => c.id === card.id);
    if (exists) return { ...prev, cards: prev.cards.map(c => c.id === card.id ? card : c) };
    return { ...prev, cards: [...(prev.cards || []), card] };
  });

  const updateCard = (card: CreditCard) => addCard(card);

  const deleteCard = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, cards: (next.cards || []).filter(c => c.id !== id) };
  });

  const addWallet = (wallet: Wallet) => setState(prev => {
    const exists = prev.wallets.some(w => w.id === wallet.id);
    if (exists) return { ...prev, wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w) };
    return { ...prev, wallets: [...(prev.wallets || []), wallet] };
  });

  const updateWallet = (wallet: Wallet) => addWallet(wallet);

  const deleteWallet = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, wallets: (next.wallets || []).filter(w => w.id !== id) };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...(prev.incomes || []), income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...(prev.expenses || []), expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...(prev.assets || []), asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...(prev.liabilities || []), liability] }));

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const amount = transaction.amount;
    const delta = (transaction.type === 'Income' || transaction.type === 'Liability') ? amount : -amount;
    const finalDelta = delta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const sharedAmt = transaction.sharedAmount || 0;
      const selfAmt = transaction.amount - sharedAmt;

      switch (transaction.type) {
        case 'Income':
          if (selfAmt > 0) newState.incomes.push({ id: transaction.id, name: transaction.description, amount: selfAmt, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Expense':
          if (selfAmt > 0) newState.expenses.push({ id: transaction.id, category: transaction.category || 'Others', amount: selfAmt, date: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: transaction.description, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: transaction.description, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    const writableMembers = state.profile.familyMembers.filter(m => m.canAddTransactions !== false);
    if (writableMembers.length === 0) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const familyNames = writableMembers.map(m => m.name).join(", ");
    const prompt = `Based on these family members: [${familyNames}], generate one realistic financial transaction that one of them might have recently made. Return ONLY a JSON object with: { memberName: string, amount: number, description: string, type: "Expense"|"Income", category: string }.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text);
      const member = writableMembers.find(m => m.name === data.memberName) || writableMembers[0];

      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: data.type,
        amount: data.amount,
        description: data.description,
        accountId: 'synced-external',
        accountType: 'bank',
        date: new Date().toISOString().split('T')[0],
        category: data.category,
        ownerId: member.id
      };

      const newNotification: Notification = {
        id: Math.random().toString(36).substr(2, 9),
        title: `Cloud Entry from ${member.name}`,
        message: `${data.description} was synchronized. Amount: ${state.profile.currency} ${data.amount.toLocaleString()}.`,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      };

      setState(prev => {
        const newState = { 
          ...prev, 
          transactions: [newTransaction, ...(prev.transactions || [])],
          notifications: [...(prev.notifications || []), newNotification] 
        };
        applyTransactionEffect(newTransaction, newState, false);
        return newState;
      });

    } catch (e) {}
  };

  const filteredState = useMemo(() => {
    // If viewing "All" (Family), we consolidate multiple "Cash" wallets into one household entry
    if (activeMemberIds.includes('all')) {
      const cashWallets = state.wallets.filter(w => w.name === 'Cash');
      const otherWallets = state.wallets.filter(w => w.name !== 'Cash');

      let consolidatedWallets = [...otherWallets];
      if (cashWallets.length > 0) {
        const totalCash = cashWallets.reduce((acc, curr) => acc + curr.balance, 0);
        consolidatedWallets.push({
          id: 'household-cash-consolidated',
          name: 'Cash',
          balance: totalCash,
          ownerId: 'family'
        });
      }

      return {
        ...state,
        wallets: consolidatedWallets
      };
    }

    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];

    const filterFn = (item: any) => {
      const ownerId = item.ownerId || '';
      return filterIds.includes(ownerId) || (filterIds.includes('') && ownerId === undefined);
    };

    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = () => { 
    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, addIncome, addExpense, addAsset, addLiability,
      addTransaction, updateTransaction, deleteTransaction, 
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares' | 'adjustment';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    totalParticipants: '2',
    splitType: 'equal' as SplitType,
    sharedAmount: '', 
    splitValue: '', 
    userShares: '1', 
    contactShares: '1',
    contacts: [] as { name: string; mobile: string }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  useEffect(() => {
    if (!formData.isShared) return;
    const totalCount = Math.max(1, parseInt(formData.totalParticipants) || 1);
    const requiredOthersCount = formData.includeSelf ? totalCount - 1 : totalCount;
    const finalCount = Math.max(0, requiredOthersCount);

    setFormData(prev => {
      const currentContacts = [...prev.contacts];
      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  const allAccounts = useMemo(() => [
    ...(state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId })),
    ...(state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId })),
    ...(state.wallets || []).map(w => ({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId })),
    ...(state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }))
  ], [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (t: Transaction) => {
    setConfirmDeleteTx(t);
  };

  const executeDelete = () => {
    if (confirmDeleteTx) {
      deleteTransaction(confirmDeleteTx.id);
      setConfirmDeleteTx(null);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source required."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-lg font-bold text-slate-800 tracking-tight">Financial Transactions</h3>
          <p className="text-xs text-slate-400 font-medium">Record and track all cash movements</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-5 py-2.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-xs font-bold hover:bg-emerald-100 transition-all shadow-sm">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-5 py-2.5 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all shadow-sm">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-5 py-2.5 bg-white text-indigo-600 border border-indigo-100 rounded-xl text-xs font-bold hover:bg-indigo-50 transition-all shadow-sm">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Description</th>
                <th className="px-6 py-5">Owner</th>
                <th className="px-6 py-5">Source</th>
                <th className="px-6 py-5 text-right">Amount</th>
                <th className="px-6 py-5 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-medium text-slate-400 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800 tracking-tight">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-50 text-indigo-600 text-[9px] font-bold px-2 py-0.5 rounded-md uppercase">Shared</span>}
                      </div>
                      {t.category && <span className="text-[10px] text-slate-400 font-bold uppercase mt-1 inline-block">{t.category}</span>}
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded-md uppercase">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <span className="text-xs text-slate-700 font-medium">{account?.name || 'Manual'}</span>
                    </td>
                    <td className={`px-6 py-4 text-sm font-black text-right ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✎</button>
                         <button onClick={() => handleDeleteClick(t)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-6 py-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <span className="text-5xl">📋</span>
                      <p className="text-sm font-bold uppercase tracking-widest text-slate-800">No Transactions Found</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 overflow-y-auto pt-16">
          <div className="bg-white w-full max-w-xl rounded-2xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
              <h3 className="text-lg font-bold text-slate-800">Record {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-600 font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Owner</label>
                  <select 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" 
                    value={formData.ownerId} 
                    onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}
                  >
                    <option value="">Me (Primary)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Account Source</label>
                  <select required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts
                      .filter(a => (a.ownerId || '') === (formData.ownerId || ''))
                      .map(acc => (
                        <option key={acc.id} value={acc.id}>{acc.name}</option>
                      ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Amount ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Date</label>
                  <input required type="date" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Description</label>
                <input required placeholder="e.g. Salary, Rent, Grocery" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold text-xs rounded-xl">Cancel</button>
                <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-indigo-100">Commit Transaction</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && (
        <DeleteTransactionConfirmationModal 
          transaction={confirmDeleteTx} 
          currency={currency}
          onCancel={() => setConfirmDeleteTx(null)} 
          onConfirm={executeDelete} 
        />
      )}
    </div>
  );
};

