      if (currentContacts.length === finalCount) return prev;
      if (currentContacts.length < finalCount) {
        for (let i = currentContacts.length; i < finalCount; i++) {
          currentContacts.push({ name: '', mobile: '' });
        }
      } else {
        currentContacts.splice(finalCount);
      }
      return { ...prev, contacts: currentContacts };
    });
  }, [formData.totalParticipants, formData.includeSelf, formData.isShared]);

  // Consolidate accounts for the selection dropdown to avoid multiple "Cash" entries per owner
  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));

    // Deduplicate/Consolidate wallets named "Cash" per owner for UI clarity
    const wallets = [];
    const ownersWithCash = new Set();

    (state.wallets || []).forEach(w => {
      if (w.name === 'Cash') {
        const ownerKey = w.ownerId || '';
        if (!ownersWithCash.has(ownerKey)) {
          wallets.push({ id: w.id, name: 'Cash', type: 'wallet' as const, ownerId: w.ownerId });
          ownersWithCash.add(ownerKey);
        }
      } else {
        wallets.push({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId });
      }
    });

    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, contacts: [] });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const nOthers = t.sharedContacts?.length || 0;
    const includeSelf = t.includeSelf ?? true;
    const totalParts = includeSelf ? nOthers + 1 : nOthers;

    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: includeSelf,
      totalParticipants: String(totalParts),
      splitType: 'equal', 
      sharedAmount: String(t.sharedAmount || ''),
      splitValue: '',
      userShares: '1',
      contactShares: '1',
      contacts: t.sharedContacts?.map(c => ({ name: c.name, mobile: c.mobile })) || [],
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleDeleteClick = (t: Transaction) => {
    setConfirmDeleteTx(t);
  };

  const executeDelete = () => {
    if (confirmDeleteTx) {
      deleteTransaction(confirmDeleteTx.id);
      setConfirmDeleteTx(null);
    }
  };

  const calculateSharedAmountTotal = () => {
    const totalValue = Number(formData.amount) || 0;
    const totalParts = Math.max(1, Number(formData.totalParticipants) || 1);
    const othersCount = formData.contacts.length;
    if (totalValue <= 0) return 0;

    switch (formData.splitType) {
      case 'equal': return (totalValue / totalParts) * othersCount;
      case 'exact': return Number(formData.sharedAmount) || 0;
      case 'percentage': return ( (Number(formData.splitValue) || 0) / 100 ) * totalValue;
      case 'shares':
        const uS = formData.includeSelf ? (Number(formData.userShares) || 1) : 0;
        const cS = Number(formData.contactShares) || 1;
        const totalShares = uS + cS;
        return totalShares > 0 ? (cS / totalShares) * totalValue : 0;
      case 'adjustment':
        const baseSharePerPerson = totalValue / totalParts;
        return (othersCount * baseSharePerPerson) + (Number(formData.splitValue) || 0);
      default: return 0;
    }
  };

  const totalOtherShare = calculateSharedAmountTotal();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source required."); return; }
    const totalAmount = Number(formData.amount);
    const finalSharedAmount = formData.isShared ? totalOtherShare : 0;

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.isShared ? Number(formData.totalParticipants) : undefined,
      sharedAmount: finalSharedAmount,
      sharedContacts: formData.isShared ? formData.contacts.map(c => ({ ...c, amount: finalSharedAmount / Math.max(1, formData.contacts.length) })) : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-lg font-bold text-slate-800 tracking-tight">Financial Transactions</h3>
          <p className="text-xs text-slate-400 font-medium">Record and track all cash movements</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-5 py-2.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-xs font-bold hover:bg-emerald-100 transition-all shadow-sm">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-5 py-2.5 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all shadow-sm">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-5 py-2.5 bg-white text-indigo-600 border border-indigo-100 rounded-xl text-xs font-bold hover:bg-indigo-50 transition-all shadow-sm">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Description</th>
                <th className="px-6 py-5">Owner</th>
                <th className="px-6 py-5">Source</th>
                <th className="px-6 py-5 text-right">Amount</th>
                <th className="px-6 py-5 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-medium text-slate-400 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800 tracking-tight">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-50 text-indigo-600 text-[9px] font-bold px-2 py-0.5 rounded-md uppercase">Shared</span>}
                      </div>
                      {t.category && <span className="text-[10px] text-slate-400 font-bold uppercase mt-1 inline-block">{t.category}</span>}
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded-md uppercase">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <span className="text-xs text-slate-700 font-medium">{account?.name || 'Manual'}</span>
                    </td>
                    <td className={`px-6 py-4 text-sm font-black text-right ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✎</button>
                         <button onClick={() => handleDeleteClick(t)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-6 py-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <span className="text-5xl">📋</span>
                      <p className="text-sm font-bold uppercase tracking-widest text-slate-800">No Transactions Found</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 overflow-y-auto pt-16">
          <div className="bg-white w-full max-w-xl rounded-2xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative">
            <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
              <h3 className="text-lg font-bold text-slate-800">Record {formData.type}</h3>
              <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-600 font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Owner</label>
                  <select 
                    className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" 
                    value={formData.ownerId} 
                    onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}
                  >
                    <option value="">Me (Primary)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Account Source</label>
                  <select required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts
                      .filter(a => (a.ownerId || '') === (formData.ownerId || ''))
                      .map(acc => (
                        <option key={acc.id} value={acc.id}>{acc.name}</option>
                      ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Amount ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Date</label>
                  <input required type="date" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Description</label>
                <input required placeholder="e.g. Salary, Rent, Grocery" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold text-xs rounded-xl">Cancel</button>
                <button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-xs shadow-lg shadow-indigo-100">Commit Transaction</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && (
        <DeleteTransactionConfirmationModal 
          transaction={confirmDeleteTx} 
          currency={currency}
          onCancel={() => setConfirmDeleteTx(null)} 
          onConfirm={executeDelete} 
        />
      )}
    </div>
  );
};

const DeleteTransactionConfirmationModal: React.FC<{ transaction: Transaction, currency: string, onCancel: () => void, onConfirm: () => void }> = ({ transaction, currency, onCancel, onConfirm }) => {
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
       <div className="w-full max-w-sm p-8 bg-white border border-slate-200 rounded-3xl shadow-2xl animate-in zoom-in duration-200">
          <div className="text-center mb-6">
             <div className="w-16 h-16 rounded-full bg-rose-50 text-rose-500 flex items-center justify-center text-3xl mx-auto mb-4 border border-rose-100">
                🗑️
             </div>
             <h4 className="text-xl font-black tracking-tight text-slate-800">
                Delete Transaction?
             </h4>
             <p className="text-sm font-medium text-slate-500 mt-2 leading-relaxed">
                This will permanently remove this entry from your ledger and reverse the balance impact.
             </p>
          </div>

          <div className="bg-slate-50 rounded-2xl p-4 mb-8 border border-slate-100">
             <div className="flex justify-between items-center mb-1">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Entry</span>
                <span className="text-[10px] font-black text-slate-800 uppercase">{transaction.date}</span>
             </div>
             <p className="text-sm font-bold text-slate-800 truncate mb-2">{transaction.description}</p>
             <div className="flex justify-between items-center">
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Value</span>
                <span className={`text-sm font-black ${transaction.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                   {transaction.type === 'Income' ? '+' : '-'}{formatCurrency(transaction.amount, currency)}
                </span>
             </div>
          </div>

          <div className="flex flex-col gap-3">
             <button onClick={onConfirm} className="w-full py-4 bg-rose-600 text-white font-bold text-sm uppercase rounded-2xl shadow-lg shadow-rose-100 hover:bg-rose-700 transition-all">Yes, Permanently Delete</button>
             <button onClick={onCancel} className="w-full py-3 bg-slate-100 text-slate-600 font-bold text-xs uppercase rounded-2xl hover:bg-slate-200 transition-all">Discard & Return</button>
          </div>
       </div>
    </div>
  );
};

export default Transactions;

import React, { useState, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

const Profile: React.FC = () => {
  const { state, updateProfile, addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission, importState, resetBoarding } = useFinance();
  const profile = state.profile;
  const [showAddMember, setShowAddMember] = useState(false);
  const [isLinking, setIsLinking] = useState(false);
  const [newMember, setNewMember] = useState({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
  const [editingCloudLabel, setEditingCloudLabel] = useState(false);
  const [cloudLabel, setCloudLabel] = useState(profile.cloudDatabaseName || '');
  const [confirmReset, setConfirmReset] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAddMember = async (e: React.FormEvent) => {
    e.preventDefault();
    if (newMember.name && newMember.mobile) {
      setIsLinking(true);
      try {
        await addFamilyMember({
          id: Math.random().toString(36).substr(2, 9),
          name: newMember.name,
          relation: newMember.relation,
          mobileNumber: newMember.mobile,
          canAddTransactions: newMember.canAddTransactions
        });

        setNewMember({ name: '', relation: 'Spouse', mobile: '', canAddTransactions: true });
        setShowAddMember(false);
      } finally {
        setIsLinking(false);
      }
    }
  };

  const handleUpdateCloudLabel = () => {
    updateProfile({ ...profile, cloudDatabaseName: cloudLabel });
    setEditingCloudLabel(false);
  };

  const handleExportData = () => {
    const dataStr = JSON.stringify(state, null, 2);
    const dataUri = 'data:application/json;charset=utf-8,'+ encodeURIComponent(dataStr);

    const exportFileDefaultName = `myfin_backup_${new Date().toISOString().split('T')[0]}.json`;

    const linkElement = document.createElement('a');
    linkElement.setAttribute('href', dataUri);
    linkElement.setAttribute('download', exportFileDefaultName);
    linkElement.click();
  };

  const handleFileImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const json = JSON.parse(event.target?.result as string);
          if (window.confirm("This will overwrite your current state with the imported backup. Continue?")) {
            importState(json);
          }
        } catch (err) {
          alert("Invalid backup file format.");
        }
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="space-y-10 max-w-4xl animate-in fade-in duration-500 pb-20">
      <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="h-40 bg-indigo-600 p-8 flex items-end relative overflow-hidden">
           <div className="absolute top-0 right-0 p-8 text-8xl font-black text-white/10 tracking-tighter select-none">MF</div>
           <div className="w-24 h-24 bg-white p-1 translate-y-12 z-10 shadow-xl rounded-2xl">
               <div className="w-full h-full bg-slate-100 flex items-center justify-center text-4xl font-black text-indigo-600 rounded-xl">
                 {profile?.name?.charAt(0) || '?'}
               </div>
           </div>
        </div>
        <div className="px-8 pt-16 pb-10">
          <div className="flex justify-between items-start mb-8">
            <div>
              <h3 className="text-3xl font-black text-slate-800 tracking-tight">{profile?.name}</h3>
              <p className="text-sm font-bold text-indigo-500 uppercase tracking-widest mt-1">{profile?.designation}</p>
            </div>
            <div className="text-right">
               <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest mb-1">Mobile</p>
               <p className="text-sm font-bold text-slate-600">+{profile?.mobileNumber}</p>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6 p-6 bg-slate-50 border border-slate-100 rounded-2xl">
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">City</p><p className="text-sm font-bold text-slate-800">{profile?.city}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Country</p><p className="text-sm font-bold text-slate-800">{profile?.country}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Currency</p><p className="text-sm font-bold text-indigo-600">{profile?.currency}</p></div>
             <div><p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Age</p><p className="text-sm font-bold text-slate-800">{profile?.age} Years</p></div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm flex flex-col justify-between">
          <div>
            <div className="flex items-center gap-3 mb-2">
              <h3 className="text-lg font-bold text-slate-800 tracking-tight">Cloud Connectivity</h3>
              <span className="text-[10px] bg-indigo-50 text-indigo-600 font-bold px-2 py-0.5 rounded">Supabase Enabled</span>
