          <div className="mt-6 flex items-center gap-3 text-[10px] text-slate-400 font-medium italic bg-indigo-50/50 p-3 rounded-xl">
             <span>☁️</span> Your data is automatically synced to the Supabase cloud using your mobile number as the key.
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-800 tracking-tight mb-2">Data Management</h3>
          <p className="text-xs text-slate-400 font-medium mb-8">Backup your financial data to a local file or restore from a previous export.</p>

          <div className="flex flex-col gap-3">
            <button 
              onClick={handleExportData}
              className="w-full px-6 py-4 bg-white border border-slate-200 text-slate-700 rounded-2xl text-xs font-bold uppercase hover:bg-slate-50 transition-all shadow-sm flex items-center justify-between"
            >
              <span className="flex items-center gap-2"><span>💾</span> Local JSON Backup</span>
              <span className="text-[10px] text-slate-400">Export</span>
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="w-full px-6 py-4 bg-indigo-50 border border-indigo-100 text-indigo-600 rounded-2xl text-xs font-bold uppercase hover:bg-indigo-100 transition-all shadow-sm flex items-center justify-between"
            >
              <span className="flex items-center gap-2"><span>📂</span> Restore from File</span>
              <span className="text-[10px] text-indigo-400 font-bold">Import</span>
            </button>
            <input type="file" ref={fileInputRef} className="hidden" accept=".json" onChange={handleFileImport} />
          </div>
        </div>
      </div>

      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <div className="flex justify-between items-center mb-10">
          <div>
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Family Members</h3>
            <p className="text-xs text-slate-400 font-medium">Shared access and permissions</p>
          </div>
          <button onClick={() => setShowAddMember(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">+ Link Member</button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {profile?.familyMembers.map(member => (
            <div key={member.id} className="p-5 bg-white border border-slate-100 rounded-2xl flex items-center justify-between group hover:border-indigo-200 transition-all shadow-sm">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-slate-50 text-indigo-600 flex items-center justify-center font-bold text-lg rounded-xl border border-slate-100">{member.name.charAt(0)}</div>
                <div>
                  <p className="text-sm font-bold text-slate-800">{member.name}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-1">{member.relation} • {member.mobileNumber}</p>
                </div>
              </div>
              <div className="flex items-center gap-4">
                <div className="flex flex-col items-end">
                  <span className="text-[9px] font-bold text-slate-400 uppercase mb-1">Sync</span>
                  <button onClick={() => toggleFamilyMemberTxPermission(member.id)} className={`relative inline-flex h-5 w-10 items-center rounded-full transition-colors ${member.canAddTransactions !== false ? 'bg-indigo-600' : 'bg-slate-200'}`}>
                    <span className={`inline-block h-3 w-3 transform bg-white rounded-full transition-transform ${member.canAddTransactions !== false ? 'translate-x-6' : 'translate-x-1'}`} />
                  </button>
                </div>
                <button onClick={() => removeFamilyMember(member.id)} className="opacity-0 group-hover:opacity-100 p-2 text-rose-400 hover:bg-rose-50 rounded-lg transition-all text-sm"> 🗑️ </button>
              </div>
            </div>
          ))}
          {profile?.familyMembers.length === 0 && (
            <div className="col-span-full py-16 text-center bg-slate-50 rounded-2xl border border-dashed border-slate-200">
               <p className="text-sm text-slate-400 font-medium">No family members linked</p>
            </div>
          )}
        </div>

        {showAddMember && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
             <div className="bg-white w-full max-w-md rounded-2xl p-8 shadow-2xl animate-in zoom-in duration-200">
               <h4 className="text-lg font-bold text-slate-800 mb-8 border-b border-slate-100 pb-4">Add Family Member</h4>
               <form onSubmit={handleAddMember} className="space-y-6">
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Full Name</label>
                    <input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.name} onChange={e => setNewMember({...newMember, name: e.target.value})} placeholder="Member Name" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Relation</label>
                    <select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.relation} onChange={e => setNewMember({...newMember, relation: e.target.value})}>
                      <option>Spouse</option><option>Child</option><option>Parent</option><option>Sibling</option><option>Partner</option>
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Mobile Number</label>
                    <input required type="tel" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={newMember.mobile} onChange={e => setNewMember({...newMember, mobile: e.target.value.replace(/\D/g, '')})} placeholder="Identification Key" />
                  </div>
                  <div className="flex gap-4 pt-6">
                    <button type="button" disabled={isLinking} onClick={() => setShowAddMember(false)} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 font-bold text-xs rounded-xl">Cancel</button>
                    <button type="submit" disabled={isLinking} className={`flex-[2] px-4 py-3 text-white font-bold text-xs rounded-xl shadow-lg transition-all flex items-center justify-center gap-2 ${isLinking ? 'bg-slate-400' : 'bg-indigo-600 shadow-indigo-100 hover:bg-indigo-700'}`}>
                      {isLinking ? <><span className="animate-spin text-sm">🔄</span> Linking & Syncing...</> : 'Link Member'}
                    </button>
                  </div>
               </form>
             </div>
          </div>
        )}
      </div>

      {/* Danger Zone Section */}
      <div className="bg-rose-50 border-2 border-rose-100 rounded-3xl p-8 shadow-sm">
        <div className="flex items-center gap-3 mb-4">
          <span className="text-2xl">⚠️</span>
          <h3 className="text-lg font-black text-rose-800 tracking-tight uppercase">Danger Zone</h3>
        </div>

        <div className="bg-white/60 p-6 rounded-2xl border border-rose-200 mb-6">
          <p className="text-sm font-black text-rose-600 uppercase tracking-widest mb-2">Warning: Absolute Destruction</p>
          <p className="text-xs font-bold text-rose-500/80 leading-relaxed uppercase">
            Resetting your account will permanently purge all financial history, linked members, bank connections, and ledger entries. 
            <br />
            <span className="text-rose-700 font-black underline">DATA WOULD NOT BE RETRIEVABLE ONCE RESET.</span>
          </p>
        </div>

        {confirmReset ? (
          <div className="flex flex-col sm:flex-row gap-4 animate-in slide-in-from-bottom-2">
            <button 
              onClick={resetBoarding}
              className="flex-1 py-4 bg-rose-600 text-white font-black text-sm uppercase rounded-2xl shadow-xl shadow-rose-200 hover:bg-rose-700 transition-all border-2 border-rose-700"
            >
              Confirm Full Reset
            </button>
            <button 
              onClick={() => setConfirmReset(false)}
              className="flex-1 py-4 bg-white text-slate-600 font-bold text-sm uppercase rounded-2xl border border-slate-200 hover:bg-slate-50 transition-all"
            >
              Abort
            </button>
          </div>
        ) : (
          <button 
            onClick={() => setConfirmReset(true)}
            className="w-full py-4 bg-white border-2 border-rose-300 text-rose-600 font-black text-sm uppercase rounded-2xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
          >
            Reset MyFin Account
          </button>
        )}
      </div>
    </div>
  );
};

export default Profile;

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { GoogleGenAI } from "@google/genai";
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => void;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: []
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', mobile)
        .single();

      if (data && data.state) {
        setState(data.state);
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({
        ...initialState,
        ...newState,
        profile: { ...initialState.profile, ...newState.profile }
      });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    if (member.mobileNumber === state.profile.mobileNumber) {
      return { success: false, syncedCount: 0, error: "Cannot link your own account as a family member." };
    }

    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) {
      return { success: false, syncedCount: 0, error: 'Member already linked.' };
    }

    let syncedCount = 0;
    let memberData: any = null;

    try {
      const { data } = await supabase
        .from('user_states')
        .select('state')
        .eq('mobile_number', member.mobileNumber)
        .single();

      if (data && data.state) {
        memberData = data.state;
      }
    } catch (err) {
      console.warn('Member vault not found for sync');
    }

    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];

      if (!memberData) {
        return {
          ...prev,
          profile: { ...prev.profile, familyMembers: newFamilyMembers }
        };
      }

      const syncTag = (item: any) => {
        const isCash = item.name === 'Cash' || item.id === 'default-cash';
        return { 
          ...item, 
          id: `${member.id}_${item.id}`, 
          name: isCash ? 'Cash' : (item.name ? `${member.name}'s ${item.name}` : undefined),
          lenderName: item.lenderName ? `${member.name}'s ${item.lenderName}` : undefined,
          ownerId: member.id 
        };
      };

      const syncTx = (tx: Transaction) => ({
        ...tx,
        id: `${member.id}_${tx.id}`,
        accountId: `${member.id}_${tx.accountId}`,
        ownerId: member.id
      });

      const newBanks = (memberData.banks || []).map(syncTag);
      const newCards = (memberData.cards || []).map(syncTag);
      const newWallets = (memberData.wallets || []).map(syncTag);
      const newTransactions = (memberData.transactions || []).map(syncTx);
      const newIncomes = (memberData.incomes || []).map(syncTag);
      const newExpenses = (memberData.expenses || []).map(syncTag);
      const newAssets = (memberData.assets || []).map(syncTag);
      const newLiabilities = (memberData.liabilities || []).map(syncTag);

      syncedCount = newBanks.length + newCards.length + newWallets.length + newTransactions.length;

      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...newBanks],
        cards: [...(prev.cards || []), ...newCards],
        wallets: [...(prev.wallets || []), ...newWallets],
        transactions: [...(prev.transactions || []), ...newTransactions],
        incomes: [...(prev.incomes || []), ...newIncomes],
        expenses: [...(prev.expenses || []), ...newExpenses],
        assets: [...(prev.assets || []), ...newAssets],
        liabilities: [...(prev.liabilities || []), ...newLiabilities],
        notifications: [...(prev.notifications || []), {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Family Sync Complete',
          message: `Successfully linked ${member.name} and synchronized ${syncedCount} financial records.`,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          type: 'sync',
          isRead: false
        }]
      };
    });

    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => 
        m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m
      )
    }
  }));

  const cleanAccountData = (prev: FinancialState, accountId: string) => {
    const transactionsToRemove = (prev.transactions || []).filter(t => t.accountId === accountId);
    const txIds = new Set(transactionsToRemove.map(t => t.id));

    return {
      ...prev,
      transactions: (prev.transactions || []).filter(t => t.accountId !== accountId),
      incomes: (prev.incomes || []).filter(i => !txIds.has(i.id)),
      expenses: (prev.expenses || []).filter(e => !txIds.has(e.id)),
      assets: (prev.assets || []).filter(a => !txIds.has(a.id) && !Array.from(txIds).some(tid => a.id.startsWith(tid + '_shared'))),
      liabilities: (prev.liabilities || []).filter(l => !txIds.has(l.id) && !Array.from(txIds).some(tid => l.id.startsWith(tid + '_shared')))
    };
  };

  const addBank = (bank: BankAccount) => setState(prev => {
    const exists = prev.banks.some(b => b.id === bank.id);
    if (exists) return { ...prev, banks: prev.banks.map(b => b.id === bank.id ? bank : b) };
    return { ...prev, banks: [...(prev.banks || []), bank] };
  });

  const updateBank = (bank: BankAccount) => addBank(bank);

  const deleteBank = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, banks: (next.banks || []).filter(b => b.id !== id) };
  });

  const addCard = (card: CreditCard) => setState(prev => {
    const exists = prev.cards.some(c => c.id === card.id);
    if (exists) return { ...prev, cards: prev.cards.map(c => c.id === card.id ? card : c) };
    return { ...prev, cards: [...(prev.cards || []), card] };
  });

  const updateCard = (card: CreditCard) => addCard(card);

  const deleteCard = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, cards: (next.cards || []).filter(c => c.id !== id) };
  });

  const addWallet = (wallet: Wallet) => setState(prev => {
    const exists = prev.wallets.some(w => w.id === wallet.id);
    if (exists) return { ...prev, wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w) };
    return { ...prev, wallets: [...(prev.wallets || []), wallet] };
  });

  const updateWallet = (wallet: Wallet) => addWallet(wallet);

  const deleteWallet = (id: string) => setState(prev => {
    const next = cleanAccountData(prev, id);
    return { ...next, wallets: (next.wallets || []).filter(w => w.id !== id) };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...(prev.incomes || []), income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...(prev.expenses || []), expense] }));
  const addAsset = (asset: Asset) => setState(prev => ({ ...prev, assets: [...(prev.assets || []), asset] }));
  const addLiability = (liability: Liability) => setState(prev => ({ ...prev, liabilities: [...(prev.liabilities || []), liability] }));

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const amount = transaction.amount;
    const delta = (transaction.type === 'Income' || transaction.type === 'Liability') ? amount : -amount;
    const finalDelta = delta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -amount : amount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const sharedAmt = transaction.sharedAmount || 0;
      const selfAmt = transaction.amount - sharedAmt;

      switch (transaction.type) {
        case 'Income':
          if (selfAmt > 0) newState.incomes.push({ id: transaction.id, name: transaction.description, amount: selfAmt, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Expense':
          if (selfAmt > 0) newState.expenses.push({ id: transaction.id, category: transaction.category || 'Others', amount: selfAmt, date: transaction.date, ownerId: transaction.ownerId });
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: transaction.description, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: transaction.description, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    const writableMembers = state.profile.familyMembers.filter(m => m.canAddTransactions !== false);
    if (writableMembers.length === 0) return;

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const familyNames = writableMembers.map(m => m.name).join(", ");
    const prompt = `Based on these family members: [${familyNames}], generate one realistic financial transaction that one of them might have recently made. Return ONLY a JSON object with: { memberName: string, amount: number, description: string, type: "Expense"|"Income", category: string }.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const data = JSON.parse(response.text);
      const member = writableMembers.find(m => m.name === data.memberName) || writableMembers[0];

      const newTransaction: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: data.type,
        amount: data.amount,
        description: data.description,
        accountId: 'synced-external',
        accountType: 'bank',
        date: new Date().toISOString().split('T')[0],
        category: data.category,
        ownerId: member.id
      };

      const newNotification: Notification = {
        id: Math.random().toString(36).substr(2, 9),
        title: `Cloud Entry from ${member.name}`,
        message: `${data.description} was synchronized. Amount: ${state.profile.currency} ${data.amount.toLocaleString()}.`,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      };

      setState(prev => {
        const newState = { 
          ...prev, 
          transactions: [newTransaction, ...(prev.transactions || [])],
          notifications: [...(prev.notifications || []), newNotification] 
        };
        applyTransactionEffect(newTransaction, newState, false);
        return newState;
      });

    } catch (e) {}
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) {
      const cashWallets = state.wallets.filter(w => w.name === 'Cash');
      const otherWallets = state.wallets.filter(w => w.name !== 'Cash');

      let consolidatedWallets = [...otherWallets];
      if (cashWallets.length > 0) {
        const totalCash = cashWallets.reduce((acc, curr) => acc + curr.balance, 0);
        consolidatedWallets.push({
          id: 'household-cash-consolidated',
          name: 'Cash',
          balance: totalCash,
          ownerId: 'family'
        });
      }

      return {
        ...state,
        wallets: consolidatedWallets
      };
    }

    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];

    const filterFn = (item: any) => {
      const ownerId = item.ownerId || '';
      return filterIds.includes(ownerId) || (filterIds.includes('') && ownerId === undefined);
    };

    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = () => { 
    const currentMobile = state.profile.mobileNumber;
    if (currentMobile) {
      localStorage.removeItem(`${STATE_PREFIX}${currentMobile}`);
    }
    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, addIncome, addExpense, addAsset, addLiability,
      addTransaction, updateTransaction, deleteTransaction, 
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

import React, { useState, useEffect, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '',
    description: '',
    accountId: '',
    category: 'Grocery',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    splitType: 'equal' as SplitType,
    participants: [] as { memberId: string; name: string; value: string; result: number }[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  // Synchronize participants when family members or owner change
  useEffect(() => {
    if (!formData.isShared) return;

    const currentOwnerId = formData.ownerId || '';
    const ownerName = currentOwnerId ? (familyMembers.find(m => m.id === currentOwnerId)?.name || 'Member') : 'Me';

    // Always include the owner/payer first if includeSelf is true
    const list = [];
    if (formData.includeSelf) {
      list.push({ memberId: currentOwnerId, name: ownerName, value: '1', result: 0 });
    }

    // Add all other family members
    familyMembers.forEach(m => {
      if (m.id !== currentOwnerId) {
        list.push({ memberId: m.id, name: m.name, value: '1', result: 0 });
      }
    });

    // If "Me" is not the owner and not in familyMembers, add "Me"
    if (currentOwnerId !== '' && formData.includeSelf) {
       // Me is not the owner, but we might want to include "Me" in the split
       // Logic: familyMembers usually doesn't include the primary user.
       if (!list.find(p => p.memberId === '')) {
         list.push({ memberId: '', name: 'Me', value: '1', result: 0 });
       }
    }

    setFormData(prev => ({ ...prev, participants: list }));
  }, [formData.isShared, formData.ownerId, formData.includeSelf, familyMembers.length]);

  // Recalculate split results whenever amounts or split types change
  const participantsWithResults = useMemo(() => {
    const totalAmount = Number(formData.amount) || 0;
    if (totalAmount <= 0 || formData.participants.length === 0) return formData.participants;

    const parts = [...formData.participants];

    if (formData.splitType === 'equal') {
      const share = totalAmount / parts.length;
      return parts.map(p => ({ ...p, result: share }));
    }

    if (formData.splitType === 'exact') {
      return parts.map(p => ({ ...p, result: Number(p.value) || 0 }));
    }

    if (formData.splitType === 'percentage') {
      return parts.map(p => ({ ...p, result: (Number(p.value) || 0) / 100 * totalAmount }));
    }

    if (formData.splitType === 'shares') {
      const totalShares = parts.reduce((acc, p) => acc + (Number(p.value) || 0), 0);
      if (totalShares === 0) return parts.map(p => ({ ...p, result: 0 }));
      return parts.map(p => ({ ...p, result: (Number(p.value) / totalShares) * totalAmount }));
    }

    return parts;
  }, [formData.amount, formData.participants, formData.splitType]);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));

    const wallets = [];
    const ownersWithCash = new Set();

    (state.wallets || []).forEach(w => {
      if (w.name === 'Cash') {
        const ownerKey = w.ownerId || '';
        if (!ownersWithCash.has(ownerKey)) {
          wallets.push({ id: w.id, name: 'Cash', type: 'wallet' as const, ownerId: w.ownerId });
          ownersWithCash.add(ownerKey);
        }
      } else {
        wallets.push({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId });
      }
    });

    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    setFormData({
      type: t.type,
      amount: String(t.amount),
      description: t.description,
      accountId: t.accountId,
      category: t.category || 'Grocery',
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      splitType: 'equal', 
      participants: [], // Will be rehydrated or handled by effect
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source account required."); return; }

    const totalAmount = Number(formData.amount);

    // Calculate shared amount (sum of what others owe)
    let sharedAmount = 0;
    let sharedContacts: SharedContact[] = [];

    if (formData.isShared) {
      const currentPayerId = formData.ownerId || '';
      const otherParticipants = participantsWithResults.filter(p => p.memberId !== currentPayerId);
      sharedAmount = otherParticipants.reduce((acc, p) => acc + p.result, 0);
      sharedContacts = otherParticipants.map(p => ({
        name: p.name,
        mobile: familyMembers.find(m => m.id === p.memberId)?.mobileNumber || 'Unknown',
        amount: p.result
      }));

      // Validation for Exact Split
      if (formData.splitType === 'exact') {
        const sum = participantsWithResults.reduce((acc, p) => acc + p.result, 0);
        if (Math.abs(sum - totalAmount) > 0.01) {
          alert(`Split amounts (${formatCurrency(sum, currency)}) must equal total (${formatCurrency(totalAmount, currency)})`);
          return;
        }
      }
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: totalAmount,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      category: (formData.type === 'Expense' || formData.type === 'Income') ? formData.category : undefined,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      sharedAmount: sharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined,
      ownerId: formData.ownerId
    };

    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const updateParticipantValue = (id: string, val: string) => {
    setFormData(prev => ({
      ...prev,
      participants: prev.participants.map(p => p.memberId === id ? { ...p, value: val } : p)
    }));
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div>
          <h3 className="text-lg font-bold text-slate-800 tracking-tight">Financial Transactions</h3>
          <p className="text-xs text-slate-400 font-medium">Record and track all cash movements</p>
        </div>
        <div className="flex flex-wrap items-center gap-3">
          <button onClick={() => handleOpenModal('Income')} className="px-5 py-2.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl text-xs font-bold hover:bg-emerald-100 transition-all shadow-sm">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-5 py-2.5 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl text-xs font-bold hover:bg-rose-100 transition-all shadow-sm">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-5 py-2.5 bg-white text-indigo-600 border border-indigo-100 rounded-xl text-xs font-bold hover:bg-indigo-50 transition-all shadow-sm">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-5 py-2.5 bg-indigo-600 text-white rounded-xl text-xs font-bold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">Liability</button>
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-bold uppercase tracking-widest border-b border-slate-200">
              <tr>
                <th className="px-6 py-5">Date</th>
                <th className="px-6 py-5">Description</th>
                <th className="px-6 py-5">Owner</th>
                <th className="px-6 py-5">Source</th>
                <th className="px-6 py-5 text-right">Amount</th>
                <th className="px-6 py-5 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {(filteredState.transactions || []).map(t => {
                const account = allAccounts.find(a => a.id === t.accountId);
                return (
                  <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="px-6 py-4 text-xs font-medium text-slate-400 whitespace-nowrap">{t.date}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-bold text-slate-800 tracking-tight">{t.description}</p>
                        {t.isShared && <span className="bg-indigo-50 text-indigo-600 text-[9px] font-bold px-2 py-0.5 rounded-md uppercase">Shared</span>}
                      </div>
                      {t.category && <span className="text-[10px] text-slate-400 font-bold uppercase mt-1 inline-block">{t.category}</span>}
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-[10px] font-bold text-slate-600 bg-slate-100 px-2 py-1 rounded-md uppercase">
                        {getOwnerName(t.ownerId)}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                       <span className="text-xs text-slate-700 font-medium">{account?.name || 'Manual'}</span>
                    </td>
                    <td className={`px-6 py-4 text-sm font-black text-right ${t.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                      {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                    </td>
                    <td className="px-6 py-4 text-center">
                       <div className="flex items-center justify-center gap-2 opacity-0 group-hover:opacity-100 transition-all">
                         <button onClick={() => handleEditClick(t)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">✎</button>
                         <button onClick={() => setConfirmDeleteTx(t)} className="p-2 text-slate-400 hover:text-rose-500 transition-colors">✕</button>
                       </div>
                    </td>
                  </tr>
                );
              })}
              {(!filteredState.transactions || filteredState.transactions.length === 0) && (
                <tr>
                  <td colSpan={6} className="px-6 py-32 text-center">
                    <div className="flex flex-col items-center gap-4 opacity-20">
                      <span className="text-5xl">📋</span>
                      <p className="text-sm font-bold uppercase tracking-widest text-slate-800">No Transactions Found</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-sm p-4 overflow-y-auto pt-10">
          <div className="bg-white w-full max-w-2xl rounded-3xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative mb-20">
            <div className="flex justify-between items-center mb-8 border-b border-slate-100 pb-4">
              <div>
                <h3 className="text-xl font-black text-slate-800 tracking-tight">Record {formData.type}</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-1">Universal Financial Entry</p>
              </div>
              <button onClick={() => setShowModal(false)} className="text-slate-300 hover:text-slate-600 font-black p-2 transition-colors">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Payer (Owner)</label>
                  <select 
                    className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" 
                    value={formData.ownerId} 
                    onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}
                  >
                    <option value="">Me (Primary)</option>
                    {familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Fund Source</label>
                  <select required className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts
                      .filter(a => (a.ownerId || '') === (formData.ownerId || ''))
                      .map(acc => (
                        <option key={acc.id} value={acc.id}>{acc.name} ({acc.type.toUpperCase()})</option>
                      ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Total Amount ({currency})</label>
                  <input required type="number" step="any" placeholder="0.00" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-2xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Transaction Date</label>
                  <input required type="date" className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block ml-1">Memo / Description</label>
                <input required placeholder="Describe this transaction..." className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
              </div>

              {/* SPLITWISE SECTION */}
              {formData.type === 'Expense' && (
                <div className="bg-indigo-50/50 p-6 rounded-3xl border border-indigo-100 space-y-6">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                       <span className="text-xl">🤝</span>
                       <h4 className="text-sm font-black text-slate-800 uppercase tracking-tight">Shared Expense</h4>
                    </div>
                    <button 
                      type="button"
                      onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))}
                      className={`relative inline-flex h-6 w-12 items-center rounded-full transition-colors ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-300'}`}
                    >
                      <span className={`inline-block h-4 w-4 transform bg-white rounded-full transition-transform ${formData.isShared ? 'translate-x-7' : 'translate-x-1'}`} />
                    </button>
                  </div>

                  {formData.isShared && (
                    <div className="space-y-6 animate-in slide-in-from-top-2 duration-300">
                      <div className="flex flex-wrap gap-2 bg-white/60 p-1 border border-indigo-100 rounded-xl">
                        {(['equal', 'exact', 'percentage', 'shares'] as SplitType[]).map(type => (
                          <button 
                            key={type}
                            type="button"
                            onClick={() => setFormData({ ...formData, splitType: type })}
                            className={`flex-1 py-2 px-4 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${formData.splitType === type ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
                          >
                            {type}
                          </button>
                        ))}
                      </div>

                      <div className="space-y-3">
                         <div className="flex justify-between items-center mb-1">
                            <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Participants & Weights</label>
                            <span className="text-[10px] font-bold text-indigo-600 bg-indigo-100 px-2 py-0.5 rounded uppercase">
                               Payer: {getOwnerName(formData.ownerId)}
                            </span>
                         </div>
                         <div className="grid grid-cols-1 gap-2">
                            {participantsWithResults.map((p, idx) => (
                              <div key={p.memberId} className="flex items-center justify-between p-4 bg-white border border-indigo-100 rounded-2xl group hover:border-indigo-300 transition-all">
                                <div className="flex items-center gap-3">
                                   <div className="w-8 h-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center font-black text-xs">
                                     {p.name.charAt(0)}
                                   </div>
                                   <div>
                                      <p className="text-xs font-black text-slate-800">{p.name}</p>
                                      <p className="text-[10px] font-bold text-slate-400 uppercase">{p.memberId === formData.ownerId ? 'Payer (Self)' : 'Participant'}</p>
                                   </div>
                                </div>
                                <div className="flex items-center gap-4">
                                   {formData.splitType !== 'equal' && (
                                     <div className="relative">
                                       <input 
                                         type="number" 
                                         className="w-20 p-2 bg-slate-50 border border-slate-200 rounded-lg text-right text-xs font-black outline-none focus:ring-2 focus:ring-indigo-500" 
                                         value={p.value} 
                                         onChange={e => updateParticipantValue(p.memberId, e.target.value)}
                                       />
                                       <span className="absolute -top-4 right-0 text-[8px] font-bold text-slate-400 uppercase">
                                          {formData.splitType === 'percentage' ? '%' : (formData.splitType === 'shares' ? 'Shares' : 'Amount')}
                                       </span>
                                     </div>
                                   )}
                                   <div className="text-right min-w-[80px]">
                                      <p className="text-xs font-black text-slate-800">{formatCurrency(p.result, currency)}</p>
                                      <p className="text-[9px] font-bold text-indigo-400 uppercase tracking-tighter">Share</p>
                                   </div>
                                </div>
                              </div>
                            ))}
                         </div>
                      </div>

                      <div className="bg-indigo-600 text-white p-5 rounded-2xl shadow-xl shadow-indigo-200 flex justify-between items-center">
                         <div>
                            <p className="text-[10px] font-bold text-indigo-200 uppercase tracking-widest">Total Shared Amount</p>
                            <p className="text-sm font-medium text-indigo-100 mt-1">What others owe you</p>
                         </div>
                         <div className="text-right">
                            <p className="text-2xl font-black tracking-tight">
                              {formatCurrency(participantsWithResults.filter(p => p.memberId !== (formData.ownerId || '')).reduce((acc, p) => acc + p.result, 0), currency)}
                            </p>
                         </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-4 bg-slate-100 text-slate-600 font-bold text-xs uppercase rounded-2xl hover:bg-slate-200 transition-all">Cancel</button>
                <button type="submit" className="flex-[2] px-4 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all">Commit to Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && (
        <DeleteTransactionConfirmationModal 
          transaction={confirmDeleteTx} 
          currency={currency}
          onCancel={() => setConfirmDeleteTx(null)} 
          onConfirm={() => {
            deleteTransaction(confirmDeleteTx.id);
            setConfirmDeleteTx(null);
          }} 
        />
      )}
    </div>
  );
};

