                                    <span className="absolute top-0 right-4 text-[9px] font-black text-slate-500 uppercase tracking-[0.2em]">
                                       {formData.splitType === 'percentage' ? 'Allocation %' : (formData.splitType === 'shares' ? 'Shares Count' : 'Exact Allocation')}
                                    </span>
                                  </div>
                                )}
                              </div>
                            ))}
                         </div>
                      </div>

                      <div className={`p-8 rounded-[2rem] transition-all duration-700 flex justify-between items-center ${splitValidation.isValid ? (formData.type === 'Income' ? 'bg-emerald-600 shadow-xl shadow-emerald-900/20' : 'bg-indigo-600 shadow-xl shadow-indigo-900/20') : 'bg-rose-600/20 border border-rose-500/50'}`}>
                         <div className="space-y-1">
                            <p className={`text-[10px] font-black uppercase tracking-[0.3em] ${splitValidation.isValid ? (formData.type === 'Income' ? 'text-emerald-200' : 'text-indigo-200') : 'text-rose-400'}`}>
                               {splitValidation.isValid ? 'Ledger Validation Success' : 'Critical: Allocation Mismatch'}
                            </p>
                            <p className={`text-sm font-bold ${splitValidation.isValid ? 'text-white' : 'text-rose-200'}`}>
                               {splitValidation.isValid ? (formData.type === 'Income' ? 'Personal Yield: ' : 'Net Outflow: ') : 'Residual Variance: '}
                               <span className="font-black text-lg">
                                  {formatCurrency(splitValidation.isValid ? (participantsWithResults.find(p => p.isSelf)?.result || 0) : splitValidation.diff, currency)}
                               </span>
                            </p>
                         </div>
                         <div className="text-right">
                            <p className={`text-[10px] font-black uppercase tracking-[0.2em] mb-2 ${formData.type === 'Income' ? 'text-emerald-200' : 'text-indigo-200'}`}>
                               {formData.type === 'Income' ? 'Total Payable to Others' : 'Total Receivable Value'}
                            </p>
                            <p className="text-3xl font-black text-white tracking-tighter">
                              {formatCurrency(participantsWithResults.filter(p => !p.isSelf).reduce((acc, p) => acc + p.result, 0), currency)}
                            </p>
                         </div>
                      </div>
                    </div>
                  )}
                </div>
              )}

              <div className="flex gap-6 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-6 bg-slate-100 text-slate-500 font-black text-[11px] uppercase tracking-widest rounded-3xl hover:bg-slate-200 transition-all">Discard</button>
                <button type="submit" className={`flex-[2.5] px-4 py-6 text-white rounded-3xl font-black text-sm uppercase tracking-[0.3em] shadow-2xl transition-all hover:scale-[1.02] active:scale-95 ${formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-200' : 'bg-indigo-600 shadow-indigo-200'}`}>Seal Record</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && (
        <DeleteTransactionConfirmationModal 
          transaction={confirmDeleteTx} 
          currency={currency}
          onCancel={() => setConfirmDeleteTx(null)} 
          onConfirm={() => {
            deleteTransaction(confirmDeleteTx.id);
            setConfirmDeleteTx(null);
          }} 
        />
      )}
    </div>
  );
};

