                            className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${formData.splitType === type ? (formData.type === 'Income' ? 'bg-emerald-600' : 'bg-indigo-600') + ' text-white shadow-xl' : 'text-slate-500 hover:text-slate-300'}`}
                          >
                            {type}
                          </button>
                        ))}
                      </div>

                      <div className="space-y-6">
                         <div className="flex justify-between items-center px-2">
                            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em]">Participant Identities</label>
                            <span className={`text-[9px] font-black ${formData.type === 'Income' ? 'text-emerald-400 bg-emerald-400/10' : 'text-indigo-400 bg-indigo-400/10'} px-4 py-1.5 rounded-full uppercase tracking-widest border border-current/20`}>
                               {formData.type === 'Income' ? 'Consignee' : 'Primary Payer'}: {getOwnerName(formData.ownerId)}
