                <button type="submit" className={`flex-[2.5] px-4 py-6 text-white rounded-3xl font-black text-sm uppercase tracking-[0.3em] shadow-2xl transition-all hover:scale-[1.02] active:scale-95 ${formData.type === 'Income' ? 'bg-emerald-600 shadow-emerald-200' : 'bg-indigo-600 shadow-indigo-100'}`}>Commit Record</button>
