          currency={currency}
          onCancel={() => setConfirmDeleteTx(null)} 
          onConfirm={() => {
            deleteTransaction(confirmDeleteTx.id);
            setConfirmDeleteTx(null);
          }} 
        />
      )}
    </div>
  );
};

const DeleteTransactionConfirmationModal: React.FC<{ transaction: Transaction, currency: string, onCancel: () => void, onConfirm: () => void }> = ({ transaction, currency, onCancel, onConfirm }) => {
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-2xl p-4">
       <div className="w-full max-w-sm p-12 bg-white border border-slate-200 rounded-[3rem] shadow-[0_50px_100px_-20px_rgba(0,0,0,0.5)] animate-in zoom-in duration-300">
          <div className="text-center mb-10">
             <div className="w-24 h-24 rounded-[2rem] bg-rose-50 text-rose-500 flex items-center justify-center text-5xl mx-auto mb-8 border border-rose-100 shadow-inner">
                🗑️
             </div>
             <h4 className="text-2xl font-black tracking-tight text-slate-800 uppercase">Void Ledger?</h4>
             <p className="text-[10px] font-black text-slate-400 mt-4 leading-relaxed uppercase tracking-[0.2em]">
                Permanently purge this entry and reverse all account impacts.
             </p>
