          <div className="bg-slate-50 rounded-[2rem] p-8 mb-12 border border-slate-100">
             <div className="flex justify-between items-center mb-3">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Entry Date</span>
                <span className="text-[10px] font-black text-slate-800 uppercase">{transaction.date}</span>
