             <p className="text-sm font-black text-slate-800 truncate mb-5">{transaction.description}</p>
             <div className="flex justify-between items-center">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Cash Impact</span>
                <span className={`text-xl font-black ${transaction.type === 'Income' ? 'text-emerald-600' : 'text-slate-800'}`}>
                   {transaction.type === 'Income' ? '+' : '-'}{formatCurrency(transaction.amount + (transaction.sharedAmount || 0), currency)}
                </span>
             </div>
          </div>

          <div className="flex flex-col gap-5">
             <button onClick={onConfirm} className="w-full py-6 bg-rose-600 text-white font-black text-xs uppercase tracking-[0.3em] rounded-3xl shadow-2xl shadow-rose-200 hover:bg-rose-700 transition-all active:scale-95">Purge Permanently</button>
