                    <button onClick={() => handleEdit('card', card)} className={`text-[10px] font-bold uppercase ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} hover:text-white transition-colors`}>Edit</button>
                    <button onClick={() => setViewingHistory(card)} className={`text-[10px] font-bold uppercase ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} hover:text-white transition-colors`}>History</button>
                    <button onClick={() => handleDelete('card', card.id, card.lenderName)} className="text-[10px] font-bold uppercase text-rose-300 hover:text-rose-500 transition-colors">Delete</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </section>

      {/* Nature of Transaction Management Section */}
      <section className="bg-white p-10 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="flex justify-between items-end mb-8">
          <div className="flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 tracking-tight">Transaction Nature Protocols</h3>
            <p className="text-xs text-slate-400 font-medium">Manage classification headers for all ledger records</p>
          </div>
        </div>
        <form onSubmit={handleAddNature} className="flex gap-4 mb-10">
          <input 
            placeholder="New Nature Label (e.g. Dividend, Subscription)" 
            className="flex-1 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-500/10 font-bold text-sm transition-all"
            value={newNature}
            onChange={e => setNewNature(e.target.value)}
          />
          <button type="submit" className="px-8 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100">Add Protocol</button>
        </form>
        <div className="flex flex-wrap gap-3">
          {(state.transactionNatures || []).map(nature => (
            <div key={nature} className="flex items-center gap-3 bg-slate-50 border border-slate-200 px-4 py-2 rounded-xl group hover:border-indigo-200 hover:bg-indigo-50 transition-all">
              <span className="text-xs font-black text-slate-700 group-hover:text-indigo-600 transition-colors uppercase tracking-tight">{nature}</span>
              <button 
                onClick={() => deleteTransactionNature(nature)}
                className="text-slate-300 hover:text-rose-500 font-bold transition-all text-sm leading-none"
              >✕</button>
            </div>
          ))}
          {(state.transactionNatures || []).length === 0 && (
            <div className="w-full py-10 text-center text-slate-300 italic text-xs">No nature protocols defined. Records will require a classification.</div>
          )}
        </div>
      </section>

      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/40 backdrop-blur-sm p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-2xl p-8 border border-slate-200 shadow-2xl animate-in zoom-in duration-200 my-8">
            <h3 className="text-lg font-bold text-slate-800 mb-6 pb-4 border-b border-slate-100">Configure {showModal?.charAt(0).toUpperCase() + showModal?.slice(1)}</h3>
            <AccountForm type={showModal} account={editingAccount} onCancel={() => { setShowModal(null); setEditingAccount(null); }} />
          </div>
        </div>
      )}
      {viewingHistory && <TransactionHistoryModal account={viewingHistory} currency={currency} onClose={() => setViewingHistory(null)} />}
      {confirmDelete && <DeleteConfirmationModal accountName={confirmDelete.name} onCancel={() => setConfirmDelete(null)} onConfirm={executeDelete} />}
    </div>
  );
};

const DeleteConfirmationModal: React.FC<{ accountName: string, onCancel: () => void, onConfirm: () => void }> = ({ accountName, onCancel, onConfirm }) => {
  const [step, setStep] = useState(1);
  const [understood, setUnderstood] = useState(false);
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4">
       <div className={`w-full max-w-sm p-8 rounded-3xl border transition-all duration-300 ${step === 2 ? 'bg-rose-50 border-rose-200' : 'bg-white border-slate-200'} shadow-2xl animate-in zoom-in duration-200`}>
          <div className="text-center mb-6">
             <div className={`w-16 h-16 rounded-full flex items-center justify-center text-3xl mx-auto mb-4 ${step === 2 ? 'bg-rose-200 text-rose-600' : 'bg-slate-100 text-slate-400'}`}>⚠️</div>
             <h4 className={`text-xl font-black tracking-tight ${step === 2 ? 'text-rose-800' : 'text-slate-800'}`}>{step === 1 ? `Delete ${accountName}?` : 'Final Confirmation Required'}</h4>
             <p className="text-sm font-medium text-slate-500 mt-2 leading-relaxed">{step === 1 ? "This account will be removed from your active dashboard." : "Are you absolutely sure?"}</p>
          </div>
          {step === 2 && (
             <label className="flex items-start gap-3 p-4 bg-white/50 border border-rose-100 rounded-xl mb-6 cursor-pointer group">
                <input type="checkbox" className="mt-1 w-4 h-4 rounded border-rose-300 text-rose-600 focus:ring-rose-500" checked={understood} onChange={e => setUnderstood(e.target.checked)} />
                <span className="text-xs font-bold text-rose-700 leading-tight">I understand this is a permanent modification.</span>
             </label>
          )}
          <div className="flex flex-col gap-3">
             {step === 1 ? (
               <>
                 <button onClick={() => setStep(2)} className="w-full py-4 bg-rose-500 text-white font-bold text-sm uppercase rounded-2xl hover:bg-rose-600 transition-all">Yes, Proceed</button>
                 <button onClick={onCancel} className="w-full py-3 bg-slate-100 text-slate-600 font-bold text-xs uppercase rounded-2xl hover:bg-slate-200 transition-all">Cancel</button>
               </>
             ) : (
               <>
                 <button disabled={!understood} onClick={onConfirm} className={`w-full py-4 font-bold text-sm uppercase rounded-2xl transition-all ${understood ? 'bg-rose-600 text-white hover:bg-rose-700' : 'bg-slate-300 text-slate-500 cursor-not-allowed'}`}>Permanently Delete</button>
                 <button onClick={onCancel} className="w-full py-3 text-slate-500 font-bold text-xs uppercase hover:underline">Discard & Return</button>
               </>
             )}
          </div>
       </div>
    </div>
  );
};

const AccountForm: React.FC<{ type: 'bank' | 'card' | 'wallet', account?: any, onCancel: () => void }> = ({ type, account, onCancel }) => {
  const { addBank, updateBank, addCard, updateCard, addWallet, updateWallet, state } = useFinance();
  const [formData, setFormData] = useState<any>(() => account ? {
    ownerId: account.ownerId || '',
    name: account.name || account.lenderName || '',
    accNum: account.accountNumber || '',
    balance: Math.abs(account.balance),
    balanceType: (account.balance < 0 && type === 'card') ? 'receivable' : 'outstanding',
    last4: account.last4 || '',
    limit: account.limit || '',
    annualLimit: account.annualLimit || '',
    anniversaryDate: account.anniversaryDate || '',
    billingDay: account.billingDay || 1,
    offers: account.offers || { movie: false, dining: false, concierge: false, lounge: false },
    accountType: account.accountType || 'Savings',
    customAccountType: account.customAccountType || ''
  } : {
    ownerId: '',
    name: '',
    balance: '',
    balanceType: 'outstanding',
    accNum: '',
    accountType: 'Savings',
    customAccountType: '',
    annualLimit: '',
    anniversaryDate: '',
    billingDay: 1,
    offers: { movie: false, dining: false, concierge: false, lounge: false }
  });
  const familyMembers = state.profile?.familyMembers || [];
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const id = account?.id || Math.random().toString(36).substr(2, 9);
    const commonProps = { id, ownerId: formData.ownerId };
    if (type === 'bank') {
      const bankData = { ...commonProps, name: formData.name, accountNumber: formData.accNum, balance: Number(formData.balance), accountType: formData.accountType, customAccountType: formData.accountType === 'Others' ? formData.customAccountType : undefined };
      account ? updateBank(bankData) : addBank(bankData);
    } else if (type === 'card') {
      const finalBalance = formData.balanceType === 'receivable' ? -Math.abs(Number(formData.balance)) : Math.abs(Number(formData.balance));
      const cardData = { ...commonProps, lenderName: formData.name, balance: finalBalance, last4: formData.last4, limit: formData.limit ? Number(formData.limit) : undefined, annualLimit: formData.annualLimit ? Number(formData.annualLimit) : undefined, anniversaryDate: formData.anniversaryDate, billingDay: Number(formData.billingDay), offers: formData.offers };
      account ? updateCard(cardData) : addCard(cardData);
    } else if (type === 'wallet') {
      const walletData = { ...commonProps, name: formData.name, balance: Number(formData.balance) };
      account ? updateWallet(walletData) : addWallet(walletData);
    }
    onCancel();
  };
  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="space-y-1"><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Owner</label><select className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.ownerId} onChange={e => setFormData({...formData, ownerId: e.target.value})}><option value="">Self (Individual)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}</select></div>
      <div className="grid grid-cols-2 gap-4"><div className="space-y-1"><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">{type === 'card' ? 'Lender' : 'Name'}</label><input required className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-sm" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} /></div><div className="space-y-1"><label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block">Opening Balance</label><input required type="number" step="any" className="w-full p-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-black text-lg" value={formData.balance} onChange={e => setFormData({...formData, balance: e.target.value})} /></div></div>
      <div className="flex gap-4 pt-6"><button type="button" onClick={onCancel} className="flex-1 px-4 py-3 bg-slate-100 text-slate-600 rounded-xl font-bold text-xs">Discard</button><button type="submit" className="flex-[2] px-4 py-3 bg-indigo-600 text-white rounded-xl font-bold text-xs">Save Asset</button></div>
    </form>
  );
};

