                  <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-10 w-20 items-center rounded-full transition-all ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-700'}`}><span className={`inline-block h-8 w-8 transform bg-white rounded-full transition-transform ${formData.isShared ? 'translate-x-11' : 'translate-x-1'}`} /></button>
