                    </div>
                    <div className="flex flex-wrap gap-2 bg-slate-800 p-2 rounded-2xl">
                      {(['equal', 'exact', 'percentage', 'shares'] as SplitType[]).map(type => (<button key={type} type="button" onClick={() => setFormData({ ...formData, splitType: type })} className={`flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${formData.splitType === type ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500 hover:text-slate-300'}`}>{type}</button>))}
                    </div>
                    <div className="space-y-4 max-h-[300px] overflow-y-auto custom-scrollbar pr-2">
                      {participantsWithResults.map((p, idx) => (
                        <div key={p.id} className="p-6 bg-slate-800/40 border border-slate-700/40 rounded-3xl space-y-4">
                          <div className="flex items-center justify-between">
                            <div className="flex items-center gap-4"><div className="w-12 h-12 rounded-2xl bg-slate-700 flex items-center justify-center font-black text-sm">{p.isSelf ? 'ME' : idx + 1}</div><div className="flex-1">{p.isSelf ? <p className="text-xs font-black text-white">{p.name} (Primary)</p> : <div className="flex gap-4"><input placeholder="Name" className="bg-transparent border-b border-slate-700 text-xs text-white outline-none w-32" value={p.name} onChange={e => updateParticipant(p.id, 'name', e.target.value)} /><input placeholder="Mobile Key" className="bg-transparent border-b border-slate-700 text-[10px] text-slate-400 outline-none w-24" value={p.mobile} onChange={e => updateParticipant(p.id, 'mobile', e.target.value)} /></div>}</div></div>
                            <div className="text-right"><p className="text-xs font-black text-white">{formatCurrency(p.result, currency)}</p><p className="text-[8px] font-black text-slate-500 uppercase mt-1">Net Share</p></div>
                          </div>
                          {formData.splitType !== 'equal' && <input type="number" className="w-full p-4 bg-slate-900 border border-slate-700 rounded-2xl text-right text-indigo-400 font-black outline-none" value={p.value} onChange={e => updateParticipant(p.id, 'value', e.target.value)} />}
                        </div>
                      ))}
                    </div>
                    <div className={`p-8 rounded-[2rem] flex justify-between items-center ${splitValidation.isValid ? 'bg-indigo-600 shadow-xl' : 'bg-rose-600/20 border border-rose-500/50'}`}>
                       <div className="space-y-1"><p className="text-[10px] font-black uppercase text-indigo-100">{splitValidation.isValid ? 'Reconciliation Valid' : 'Gap Detected'}</p><p className="text-sm font-bold text-white">Net Asset Delta: <span className="font-black text-xl">{formatCurrency(participantsWithResults.find(p => p.isSelf)?.result || 0, currency)}</span></p></div>
                       <div className="text-right"><p className="text-[10px] font-black uppercase text-indigo-100 mb-2">Owed {formData.type === 'Income' ? 'to Others' : 'by Others'}</p><p className="text-3xl font-black text-white">{formatCurrency(participantsWithResults.filter(p => !p.isSelf).reduce((acc, p) => acc + p.result, 0), currency)}</p></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="flex gap-6 pt-6">
                <button type="button" onClick={() => setShowModal(false)} className="flex-1 px-4 py-6 bg-slate-100 text-slate-500 font-black text-[11px] uppercase tracking-widest rounded-3xl">Discard</button>
                <button type="submit" className="flex-[2.5] px-4 py-6 bg-indigo-600 text-white rounded-3xl font-black text-sm uppercase tracking-widest shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">Commit Execution</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && <DeleteTransactionConfirmationModal transaction={confirmDeleteTx} currency={currency} onCancel={() => setConfirmDeleteTx(null)} onConfirm={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} />}
    </div>
  );
};

