import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleScroll = () => {
      if (mainRef.current) {
        setIsShrunk(mainRef.current.scrollTop > 40);
      }
    };
    const currentMain = mainRef.current;
    if (currentMain) {
      currentMain.addEventListener('scroll', handleScroll);
    }
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Home', icon: '📊' },
    { id: 'transactions', label: 'Cash', icon: '💸' },
    { id: 'accounts', label: 'Vault', icon: '🏦' },
    { id: 'statements', label: 'Reports', icon: '📜' },
    { id: 'profile', label: 'You', icon: '👤' },
  ];

  return (
    <div className="h-screen flex flex-col md:flex-row bg-slate-50 font-sans selection:bg-indigo-100 overflow-hidden">
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex w-64 bg-slate-900 border-r border-slate-800 z-30 flex-col text-white sticky top-0 h-screen">
        <div className="p-8">
          <div className="flex items-center gap-3">
             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <p className="text-xs font-medium text-slate-400 mt-1 uppercase tracking-widest">Finance Suite</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}

          <div className="pt-10 space-y-1">
             <p className="px-5 text-[10px] font-bold text-slate-600 uppercase tracking-widest mb-2">Session</p>
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase"
            >
              <span>🚪</span> Sign Out
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden">
        {/* Morphing Header */}
        <header className={`sticky top-0 bg-white/80 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all duration-300 morph-header ${isShrunk ? 'h-14' : 'h-20'} pt-[var(--sat)]`}>
          <div className="flex items-center gap-4">
            <div className="md:hidden flex items-center gap-2">
               <div className={`bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white transition-all ${isShrunk ? 'w-7 h-7 text-xs' : 'w-9 h-9 text-sm'}`}>M</div>
               {!isShrunk && <span className="font-black text-slate-800 tracking-tighter text-lg">MyFin</span>}
            </div>

            <div className="flex items-center gap-2">
              <button 
                onClick={handleSync}
                disabled={isSyncing}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  isSyncing 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-indigo-600 text-white shadow-md active:scale-95'
                }`}
              >
                <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
                <span className={isShrunk ? 'hidden' : 'inline'}>{isSyncing ? 'Syncing' : 'Sync'}</span>
              </button>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-full">
              <button 
                onClick={() => setActiveMemberIds([])}
                className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${currentView === 'me' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
              > Me </button>
              <button 
                onClick={() => setActiveMemberIds(['all'])}
                className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
              > Fam </button>
            </div>

            <div className="relative" ref={notificationsRef}>
               <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-2 bg-slate-100 rounded-lg text-slate-600">
                 <span className="text-lg">🔔</span>
                 {unreadCount > 0 && <span className="absolute -top-1 -right-1 bg-rose-500 w-2 h-2 rounded-full border border-white"></span>}
               </button>
               {showNotifications && (
                <div className="absolute top-full right-0 mt-2 w-72 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-[9px] font-black text-slate-800 uppercase tracking-widest">Alerts</h4>
                    <button onClick={clearNotifications} className="text-[9px] font-black text-indigo-600 uppercase">Clear</button>
                  </div>
                  <div className="max-h-80 overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-50' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[11px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                          <span className="text-[8px] font-bold text-slate-400">{n.timestamp}</span>
                        </div>
                        <p className="text-[10px] text-slate-500 font-medium leading-relaxed">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-10 text-center text-slate-300 italic text-xs">No notifications</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full pb-24 md:pb-8">
          {children}
        </div>

        {/* Mobile Bottom Navigation */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-slate-200 flex items-center justify-around px-2 pt-2 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] z-50 shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)]">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`flex flex-col items-center gap-1 transition-all px-4 ${
                activeTab === item.id ? 'text-indigo-600 scale-105' : 'text-slate-400'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className={`text-[8px] font-black uppercase tracking-[0.15em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState } from 'react';
import { useFinance } from '../store/FinanceContext';

const countries = [
  { name: 'India', currency: 'INR' }, { name: 'United Kingdom', currency: 'GBP' }, { name: 'United States', currency: 'USD' },
  { name: 'Singapore', currency: 'SGD' }, { name: 'United Arab Emirates', currency: 'AED' }, { name: 'Japan', currency: 'JPY' }
];

const Onboarding: React.FC = () => {
  const { state, updateProfile, setAuthenticated, addWallet, loadStateFromCloud } = useFinance();
  const [authState, setAuthState] = useState<'MOBILE' | 'MFA' | 'PROFILE'>('MOBILE');
  const [mobileNumber, setMobileNumber] = useState('');
  const [otp, setOtp] = useState(['', '', '', '']);
  const [isVerifyingCloud, setIsVerifyingCloud] = useState(false);
  const [isExistingUser, setIsExistingUser] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    designation: '',
    age: '',
    city: '',
    country: 'India',
    currency: 'INR',
    openingCash: '0'
  });

  const handleSendOtp = async (e: React.FormEvent) => {
    e.preventDefault();
    if (mobileNumber.length >= 8) {
      setIsVerifyingCloud(true);
      const exists = await loadStateFromCloud(mobileNumber);
      setIsExistingUser(exists);
      setIsVerifyingCloud(false);
      setAuthState('MFA');
    }
  };

  const handleVerifyMfa = (e: React.FormEvent) => {
    e.preventDefault();
    if (otp.every(d => d !== '')) {
      if (isExistingUser) setAuthenticated(true);
      else setAuthState('PROFILE');
    }
  };

  const handleProfileSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    updateProfile({ 
      ...formData, 
      age: Number(formData.age), 
      mobileNumber, 
      isBoarded: true, 
      familyMembers: [],
      cloudDatabaseName: 'Default_Vault'
    });

    addWallet({ id: 'default-cash', name: 'Cash', balance: Number(formData.openingCash) });
    setAuthenticated(true);
  };

  const containerClasses = "min-h-[100dvh] bg-white md:bg-slate-50 flex items-stretch md:items-center justify-center overflow-hidden";
  const cardClasses = "w-full md:max-w-md bg-white p-8 md:p-12 md:rounded-[3rem] md:shadow-2xl md:border md:border-slate-100 flex flex-col justify-center animate-in fade-in zoom-in-95 duration-500";

  if (authState === 'MOBILE') {
    return (
      <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12 text-center">
            <div className="w-16 h-16 bg-indigo-600 text-white rounded-3xl flex items-center justify-center text-3xl font-black mx-auto mb-6 shadow-xl shadow-indigo-200">M</div>
            <h1 className="text-4xl font-black tracking-tighter text-slate-900">MyFin</h1>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-3">Private Wealth Portal</p>
          </div>

          <form onSubmit={handleSendOtp} className="space-y-10">
            <div className="space-y-4">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-1">Authentication Key</label>
              <div className="relative border-b-4 border-slate-100 pb-4 focus-within:border-indigo-600 transition-all duration-300">
                <div className="flex items-center">
                  <span className="text-slate-400 font-black text-2xl mr-2">+</span>
                  <input 
                    required 
                    type="tel" 
                    autoFocus
                    placeholder="Mobile Number" 
                    className="w-full bg-transparent outline-none font-black text-3xl tracking-tight text-slate-900 placeholder:text-slate-200" 
                    value={mobileNumber} 
                    onChange={e => setMobileNumber(e.target.value.replace(/\D/g, ''))} 
                  />
                </div>
              </div>
            </div>

            <button 
              type="submit" 
              disabled={isVerifyingCloud || mobileNumber.length < 8} 
              className={`w-full py-6 text-white font-black text-xs uppercase tracking-widest rounded-3xl transition-all shadow-xl flex items-center justify-center gap-3 ${isVerifyingCloud || mobileNumber.length < 8 ? 'bg-slate-200 text-slate-400' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100 active:scale-95'}`}
            >
              {isVerifyingCloud ? (<><span className="animate-spin">⚙️</span> Syncing...</>) : 'Request Access'}
            </button>
          </form>

          <p className="mt-12 text-[10px] text-slate-400 text-center font-bold leading-relaxed uppercase tracking-widest opacity-60">
            Secure End-to-End Encryption Enabled
          </p>
        </div>
      </div>
    );
  }

  if (authState === 'MFA') {
    return (
      <div className={containerClasses}>
        <div className={cardClasses}>
          <div className="mb-12">
            <h2 className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-3">Security Check</h2>
            <p className="text-2xl font-black text-slate-900 tracking-tight">Enter verification code sent to <span className="text-indigo-600">+{mobileNumber}</span></p>
          </div>
          <div className="flex justify-between gap-3 mb-12">
            {otp.map((digit, i) => (
              <input 
                key={i} 
                id={`otp-${i}`} 
                required 
                type="number" 
                className="w-full h-20 text-center text-4xl font-black bg-slate-50 border-2 border-transparent rounded-3xl focus:border-indigo-600 focus:bg-white outline-none transition-all" 
                value={digit} 
                onChange={e => {
                  const n = [...otp]; n[i] = e.target.value.slice(-1); setOtp(n);
                  if (e.target.value && i < 3) document.getElementById(`otp-${i+1}`)?.focus();
                }} 
              />
            ))}
          </div>
          <button 
            onClick={handleVerifyMfa} 
            disabled={otp.some(d => d === '')}
            className={`w-full py-6 font-black text-xs uppercase tracking-widest rounded-3xl shadow-xl transition-all ${otp.some(d => d === '') ? 'bg-slate-100 text-slate-400' : 'bg-slate-900 text-white hover:bg-black shadow-slate-200'}`}
          >
            {isExistingUser ? 'Restore & Vault' : 'Validate Session'}
          </button>
          <button onClick={() => setAuthState('MOBILE')} className="mt-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center hover:text-indigo-600 transition-colors">Wrong number?</button>
        </div>
      </div>
    );
  }

  return (
    <div className={containerClasses}>
      <div className="w-full md:max-w-2xl bg-white p-8 md:p-16 md:rounded-[3rem] md:shadow-2xl md:border md:border-slate-100 flex flex-col justify-center animate-in fade-in duration-500 overflow-y-auto">
        <div className="mb-12">
          <h2 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Vault Setup</h2>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.3em] mt-3">Localization Protocols</p>
        </div>

        <form onSubmit={handleProfileSubmit} className="space-y-10">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Legal Name</label>
              <input required placeholder="Your Full Name" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
            </div>
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Profession</label>
              <input required placeholder="Designation" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.designation} onChange={e => setFormData({...formData, designation: e.target.value})} />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12">
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">City</label>
              <input required placeholder="Current City" className="w-full bg-transparent outline-none font-black text-xl text-slate-900 placeholder:text-slate-200" value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} />
            </div>
            <div className="space-y-3 border-b-2 border-slate-100 pb-3 focus-within:border-indigo-600 transition-all">
              <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Currency Base</label>
              <select className="w-full bg-transparent outline-none font-black text-xl text-slate-900 cursor-pointer" value={formData.country} onChange={e => {
                const country = countries.find(c => c.name === e.target.value);
                setFormData({...formData, country: e.target.value, currency: country?.currency || 'USD'});
              }}>
                {countries.map(c => <option key={c.name} value={c.name}>{c.name}</option>)}
              </select>
            </div>
          </div>

          <div className="space-y-3 border-b-2 border-slate-100 pb-4 focus-within:border-indigo-600 transition-all">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Initial Liquidity (Cash)</label>
            <div className="flex items-center">
              <span className="text-indigo-600 font-black text-2xl mr-2">{formData.currency}</span>
              <input type="number" step="any" placeholder="0.00" className="w-full bg-transparent outline-none font-black text-4xl text-slate-900" value={formData.openingCash} onChange={e => setFormData({...formData, openingCash: e.target.value})} />
            </div>
          </div>

          <button type="submit" className="w-full py-6 bg-indigo-600 text-white font-black text-xs uppercase tracking-[0.2em] rounded-3xl shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95">Initialize Portal</button>
        </form>
      </div>
    </div>
  );
};

