import React, { useState, useEffect, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab }) => {
  const { state, activeMemberIds, isCloudSyncing, setActiveMemberIds, resetBoarding, simulateSync, markNotificationRead, clearNotifications } = useFinance();
  const [showNotifications, setShowNotifications] = useState(false);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isShrunk, setIsShrunk] = useState(false);

  const mainRef = useRef<HTMLDivElement>(null);
  const notificationsRef = useRef<HTMLDivElement>(null);
  const familyMembers = state.profile?.familyMembers || [];
  const unreadCount = state.notifications.filter(n => !n.isRead).length;

  useEffect(() => {
    const handleScroll = () => {
      if (mainRef.current) {
        setIsShrunk(mainRef.current.scrollTop > 40);
      }
    };
    const currentMain = mainRef.current;
    if (currentMain) {
      currentMain.addEventListener('scroll', handleScroll);
    }
    return () => currentMain?.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (notificationsRef.current && !notificationsRef.current.contains(event.target as Node)) {
        setShowNotifications(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const currentView = activeMemberIds.includes('all') 
    ? 'family' 
    : (activeMemberIds.length === 0 ? 'me' : 'custom');

  const handleSync = async () => {
    setIsSyncing(true);
    await simulateSync();
    setIsSyncing(false);
  };

  const navItems = [
    { id: 'dashboard', label: 'Home', icon: '📊' },
    { id: 'transactions', label: 'Cash', icon: '💸' },
    { id: 'accounts', label: 'Vault', icon: '🏦' },
    { id: 'statements', label: 'Reports', icon: '📜' },
    { id: 'profile', label: 'You', icon: '👤' },
