              <button 
                onClick={() => setActiveMemberIds(['all'])}
                className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
              > Fam </button>
            </div>

            <div className="relative" ref={notificationsRef}>
               <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-2 bg-slate-100 rounded-lg text-slate-600">
                 <span className="text-lg">🔔</span>
                 {unreadCount > 0 && <span className="absolute -top-1 -right-1 bg-rose-500 w-2 h-2 rounded-full border border-white"></span>}
               </button>
               {showNotifications && (
                <div className="absolute top-full right-0 mt-2 w-72 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-[9px] font-black text-slate-800 uppercase tracking-widest">Alerts</h4>
                    <button onClick={clearNotifications} className="text-[9px] font-black text-indigo-600 uppercase">Clear</button>
                  </div>
                  <div className="max-h-80 overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-50' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[11px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                          <span className="text-[8px] font-bold text-slate-400">{n.timestamp}</span>
                        </div>
                        <p className="text-[10px] text-slate-500 font-medium leading-relaxed">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-10 text-center text-slate-300 italic text-xs">No notifications</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-3 md:p-8 max-w-7xl mx-auto w-full pb-24 md:pb-8">
          {children}
        </div>

        {/* Mobile Bottom Navigation */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-slate-200 flex items-center justify-around px-2 pt-2 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] z-50 shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)]">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`flex flex-col items-center gap-1 transition-all px-4 ${
                activeTab === item.id ? 'text-indigo-600 scale-105' : 'text-slate-400'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className={`text-[8px] font-black uppercase tracking-[0.15em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useMemo } from 'react';
import { useFinance } from '../store/FinanceContext';
import { formatCurrency } from '../utils/formatters';
import { Transaction, CreditCard } from '../types';

const Accounts: React.FC = () => {
  const { filteredState, state, deleteBank, deleteCard, deleteWallet, addTransactionNature, deleteTransactionNature } = useFinance();
  const [showModal, setShowModal] = useState<'bank' | 'card' | 'wallet' | null>(null);
  const [editingAccount, setEditingAccount] = useState<any>(null);
  const [viewingHistory, setViewingHistory] = useState<any>(null);
  const [confirmDelete, setConfirmDelete] = useState<{ id: string, type: 'bank' | 'card' | 'wallet', name: string } | null>(null);
  const [newNature, setNewNature] = useState('');

  const currency = filteredState.profile.currency;

  const getOwnerName = (ownerId?: string) => {
    if (!ownerId) return 'Me';
    const member = (state.profile?.familyMembers || []).find(m => m.id === ownerId);
    return member ? member.name : 'Individual';
  };

  const calculateAnnualSpend = (card: CreditCard) => {
    if (!card.annualLimit || !card.anniversaryDate) return 0;
    const now = new Date();
    const anniv = new Date(card.anniversaryDate);
    let cycleStart = new Date(now.getFullYear(), anniv.getMonth(), anniv.getDate());
    if (cycleStart > now) cycleStart.setFullYear(cycleStart.getFullYear() - 1);
    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const calculateCycleDues = (card: CreditCard) => {
    if (!card.billingDay) return card.balance;
    const now = new Date();
    let cycleStart = new Date(now.getFullYear(), now.getMonth(), card.billingDay);
    if (cycleStart > now) cycleStart.setMonth(cycleStart.getMonth() - 1);
    return (filteredState.transactions || [])
      .filter(t => t.accountId === card.id && t.type === 'Expense' && new Date(t.date) >= cycleStart)
      .reduce((acc, t) => acc + t.amount, 0);
  };

  const handleEdit = (type: 'bank' | 'card' | 'wallet', account: any) => {
    setEditingAccount(account);
    setShowModal(type);
  };

  const handleDelete = (type: 'bank' | 'card' | 'wallet', id: string, name: string) => {
    setConfirmDelete({ id, type, name });
  };

  const executeDelete = () => {
    if (!confirmDelete) return;
    if (confirmDelete.type === 'bank') deleteBank(confirmDelete.id);
    else if (confirmDelete.type === 'card') deleteCard(confirmDelete.id);
    else if (confirmDelete.type === 'wallet') deleteWallet(confirmDelete.id);
    setConfirmDelete(null);
  };

  const handleAddNature = (e: React.FormEvent) => {
    e.preventDefault();
    if (newNature.trim()) {
      addTransactionNature(newNature.trim());
      setNewNature('');
    }
  };

  return (
    <div className="space-y-8 md:space-y-12 animate-in fade-in duration-500 pb-20">
      {/* Depository Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Depository Accounts</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Savings & Checking</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('bank'); }}
            className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100"
          >
            + Add Bank
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.banks || []).map(bank => (
            <div key={bank.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full">{getOwnerName(bank.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center text-xl">🏦</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-lg font-black text-slate-800 tracking-tight">{formatCurrency(bank.balance, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{bank.name}</h4>
                 <p className="text-[10px] font-medium text-indigo-500 mt-1 uppercase tracking-widest">
                    {bank.accountType === 'Others' ? bank.customAccountType : bank.accountType}
                 </p>
              </div>
              <p className="text-[10px] font-mono text-slate-400">{bank.accountNumber || '**** **** ****'}</p>
              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('bank', bank)} className="text-[9px] font-bold uppercase text-indigo-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(bank)} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('bank', bank.id, bank.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Wallets Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Wallets</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Cash & Digital</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('wallet'); }}
            className="px-4 py-2 bg-emerald-600 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-emerald-700 transition-all shadow-md shadow-emerald-100"
          >
            + Add Wallet
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 md:gap-6">
          {(filteredState.wallets || []).map(wallet => (
            <div key={wallet.id} className="bg-white p-5 md:p-6 rounded-2xl border border-slate-200 relative group transition-all shadow-sm">
              <span className="absolute top-4 right-4 text-[8px] font-bold uppercase text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">{getOwnerName(wallet.ownerId)}</span>
              <div className="flex justify-between items-start mb-6">
                <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center text-xl">👛</div>
                <div className="text-right">
                  <p className="text-[9px] text-slate-400 font-bold uppercase tracking-widest mb-1">Balance</p>
                  <p className="text-lg font-black text-slate-800 tracking-tight">{formatCurrency(wallet.balance, currency)}</p>
                </div>
              </div>
              <div className="mb-4">
                 <h4 className="text-sm font-bold text-slate-800">{wallet.name}</h4>
                 <p className="text-[9px] font-bold text-emerald-500 mt-1 uppercase tracking-widest">On-Hand</p>
              </div>
              <div className="flex gap-4 pt-4 border-t border-slate-50 mt-4">
                <button onClick={() => handleEdit('wallet', wallet)} className="text-[9px] font-bold uppercase text-emerald-600 hover:underline">Edit</button>
                <button onClick={() => setViewingHistory(wallet)} className="text-[9px] font-bold uppercase text-slate-400 hover:text-slate-600 transition-colors">History</button>
                <button onClick={() => handleDelete('wallet', wallet.id, wallet.name)} className="text-[9px] font-bold uppercase text-rose-400 hover:text-rose-600 ml-auto">Delete</button>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Credit Section */}
      <section>
        <div className="flex justify-between items-end mb-6 md:mb-8">
          <div className="flex flex-col">
            <h3 className="text-base md:text-lg font-bold text-slate-800 tracking-tight">Credit Lines</h3>
            <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest">Cards & Overdrafts</p>
          </div>
          <button 
            onClick={() => { setEditingAccount(null); setShowModal('card'); }}
            className="px-4 py-2 bg-slate-800 text-white rounded-xl text-[10px] font-bold uppercase hover:bg-slate-900 transition-all shadow-md"
          >
            + New Card
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-8">
          {(filteredState.cards || []).map(card => {
            const isReceivable = card.balance < 0;
            const annualUsed = calculateAnnualSpend(card);
            const cycleDues = calculateCycleDues(card);
            const annualLimit = card.annualLimit || 0;
            const spendPercentage = annualLimit > 0 ? (annualUsed / annualLimit) * 100 : 0;

            return (
              <div key={card.id} className={`relative overflow-hidden bg-gradient-to-br ${isReceivable ? 'from-emerald-600 to-emerald-800' : 'from-indigo-600 to-indigo-800'} p-6 md:p-8 rounded-3xl text-white shadow-xl group flex flex-col justify-between min-h-[280px] md:min-h-[320px]`}>
                <span className="absolute top-6 right-6 text-[8px] font-bold uppercase text-white/40 tracking-widest">{getOwnerName(card.ownerId)}</span>
                <div className="relative z-10">
                  <div className="flex justify-between items-start mb-6 md:mb-8">
                    <div>
                      <div className="flex items-center gap-2 mb-1">
                        <p className={`text-[8px] md:text-[10px] ${isReceivable ? 'text-emerald-200' : 'text-indigo-200'} font-bold uppercase tracking-widest`}>
                          {isReceivable ? 'Receivable' : 'Outstanding'}
