             <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center font-bold">M</div>
             <h1 className="text-xl font-bold tracking-tight">MyFin</h1>
          </div>
          <p className="text-xs font-medium text-slate-400 mt-1 uppercase tracking-widest">Finance Suite</p>
        </div>

        <nav className="flex-1 px-4 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center gap-4 px-5 py-3 rounded-xl text-sm font-medium transition-all ${
                activeTab === item.id 
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-900/20' 
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {item.label}
            </button>
          ))}

          <div className="pt-10 space-y-1">
             <p className="px-5 text-[10px] font-bold text-slate-600 uppercase tracking-widest mb-2">Session</p>
             <button
              onClick={resetBoarding}
              className="w-full flex items-center gap-4 px-5 py-3 rounded-xl text-xs font-medium text-slate-500 hover:text-rose-400 transition-colors uppercase"
            >
              <span>🚪</span> Sign Out
            </button>
          </div>
        </nav>
      </aside>

      {/* Main Content Area */}
      <main ref={mainRef} className="flex-1 flex flex-col relative h-full overflow-y-auto overflow-x-hidden">
        {/* Morphing Header */}
        <header className={`sticky top-0 bg-white/80 backdrop-blur-xl border-b border-slate-200 px-4 md:px-8 z-40 flex justify-between items-center transition-all duration-300 morph-header ${isShrunk ? 'h-14' : 'h-20'} pt-[var(--sat)]`}>
          <div className="flex items-center gap-4">
            <div className="md:hidden flex items-center gap-2">
               <div className={`bg-indigo-600 rounded-lg flex items-center justify-center font-bold text-white transition-all ${isShrunk ? 'w-7 h-7 text-xs' : 'w-9 h-9 text-sm'}`}>M</div>
               {!isShrunk && <span className="font-black text-slate-800 tracking-tighter text-lg">MyFin</span>}
            </div>

            <div className="flex items-center gap-2">
              <button 
                onClick={handleSync}
                disabled={isSyncing}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  isSyncing 
                    ? 'bg-slate-100 text-slate-400' 
                    : 'bg-indigo-600 text-white shadow-md active:scale-95'
                }`}
              >
                <span className={isSyncing ? 'animate-spin' : ''}>🔄</span>
                <span className={isShrunk ? 'hidden' : 'inline'}>{isSyncing ? 'Syncing' : 'Sync'}</span>
              </button>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <div className="flex items-center gap-1 bg-slate-100 p-1 rounded-full">
              <button 
                onClick={() => setActiveMemberIds([])}
                className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${currentView === 'me' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
              > Me </button>
              <button 
                onClick={() => setActiveMemberIds(['all'])}
                className={`px-3 py-1 rounded-full text-[9px] font-black uppercase transition-all ${currentView === 'family' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
              > Fam </button>
            </div>

            <div className="relative" ref={notificationsRef}>
               <button onClick={() => setShowNotifications(!showNotifications)} className="relative p-2 bg-slate-100 rounded-lg text-slate-600">
                 <span className="text-lg">🔔</span>
                 {unreadCount > 0 && <span className="absolute -top-1 -right-1 bg-rose-500 w-2 h-2 rounded-full border border-white"></span>}
               </button>
               {showNotifications && (
                <div className="absolute top-full right-0 mt-2 w-72 bg-white border border-slate-200 rounded-2xl shadow-2xl z-50 overflow-hidden animate-in fade-in slide-in-from-top-2">
                  <div className="p-3 border-b border-slate-100 flex justify-between items-center bg-slate-50/50">
                    <h4 className="text-[9px] font-black text-slate-800 uppercase tracking-widest">Alerts</h4>
                    <button onClick={clearNotifications} className="text-[9px] font-black text-indigo-600 uppercase">Clear</button>
                  </div>
                  <div className="max-h-80 overflow-y-auto custom-scrollbar">
                    {state.notifications.length > 0 ? [...state.notifications].reverse().map(n => (
                      <div key={n.id} onClick={() => markNotificationRead(n.id)} className={`p-4 border-b border-slate-50 transition-colors cursor-pointer hover:bg-slate-50 ${n.isRead ? 'opacity-50' : 'bg-white'}`}>
                        <div className="flex justify-between items-start mb-1">
                          <p className="text-[11px] font-black text-slate-800 uppercase leading-tight">{n.title}</p>
                          <span className="text-[8px] font-bold text-slate-400">{n.timestamp}</span>
                        </div>
                        <p className="text-[10px] text-slate-500 font-medium leading-relaxed">{n.message}</p>
                      </div>
                    )) : (
                      <div className="p-10 text-center text-slate-300 italic text-xs">No notifications</div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        </header>

        <div className="flex-1 p-3 md:p-8 max-w-7xl mx-auto w-full pb-24 md:pb-8">
          {children}
        </div>

        {/* Mobile Bottom Navigation */}
        <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-xl border-t border-slate-200 flex items-center justify-around px-2 pt-2 pb-[calc(env(safe-area-inset-bottom)+0.75rem)] z-50 shadow-[0_-10px_20px_-5px_rgba(0,0,0,0.05)]">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`flex flex-col items-center gap-1 transition-all px-4 ${
                activeTab === item.id ? 'text-indigo-600 scale-105' : 'text-slate-400'
              }`}
            >
              <span className="text-xl">{item.icon}</span>
              <span className={`text-[8px] font-black uppercase tracking-[0.15em] ${activeTab === item.id ? 'opacity-100' : 'opacity-40'}`}>{item.label}</span>
            </button>
          ))}
        </nav>
      </main>
    </div>
  );
};

export default Layout;

export type Periodicity = 'Daily' | 'Weekly' | 'Monthly' | 'Yearly';

export interface FamilyMember {
  id: string;
  name: string;
  relation: string;
  mobileNumber: string;
  canAddTransactions?: boolean;
}

export interface UserProfile {
  name: string;
  designation: string;
  age: number;
  city: string;
  country: string;
  currency: string;
  mobileNumber?: string;
  isBoarded: boolean;
  familyMembers: FamilyMember[];
  cloudDatabaseName?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  timestamp: string;
  type: 'transaction' | 'system' | 'sync';
  isRead: boolean;
}

export interface BankAccount {
  id: string;
  name: string;
  accountNumber?: string;
  balance: number;
  ownerId?: string;
  accountType?: 'Savings' | 'Current' | 'Salary' | 'Others';
  customAccountType?: string;
}

export interface CreditCard {
  id: string;
  lenderName: string;
  balance: number;
  last4: string;
  limit?: number;
  annualLimit?: number; 
  anniversaryDate?: string;
  billingDay?: number;
  offers: {
    movie: boolean;
    dining: boolean;
    concierge: boolean;
    lounge: boolean;
  };
  ownerId?: string;
}

export interface Wallet {
  id: string;
  name: string;
  balance: number;
  ownerId?: string;
}

export interface IncomeStream {
  id: string;
  name: string;
  amount: number;
  periodicity: Periodicity;
  dateOfReceipt: string;
  ownerId?: string;
}

export interface Expense {
  id: string;
  category: string;
  amount: number;
  date: string;
  periodicity?: Periodicity;
  ownerId?: string;
}

export interface Asset {
  id: string;
  name: string;
  value: number;
  type?: 'Physical' | 'Receivable';
  ownerId?: string;
}

export interface Liability {
  id: string;
  name: string;
  amount: number;
  type?: 'Debt' | 'Payable';
  ownerId?: string;
}

export type TransactionType = 'Income' | 'Expense' | 'Asset' | 'Liability';

export interface SharedContact {
  name: string;
  mobile: string;
  amount: number;
}

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  nature: string; // Mandatory nature of transaction
  description: string;
  accountId: string;
  accountType: 'bank' | 'card' | 'wallet' | 'liability';
  date: string;
  category?: string;
  isShared?: boolean;
  sharedAmount?: number;
  numberOfPeople?: number;
  includeSelf?: boolean;
  sharedContacts?: SharedContact[];
  ownerId?: string; 
}

export interface FinancialState {
  profile: UserProfile;
  banks: BankAccount[];
  cards: CreditCard[];
  wallets: Wallet[];
  incomes: IncomeStream[];
  expenses: Expense[];
  assets: Asset[];
  liabilities: Liability[];
  transactions: Transaction[];
  notifications: Notification[];
  transactionNatures: string[]; 
  capital: number; // Tracks initial equity and capital contributions
}

import React, { createContext, useContext, useState, useEffect, ReactNode, useMemo } from 'react';
import { FinancialState, UserProfile, BankAccount, CreditCard, Wallet, IncomeStream, Expense, Asset, Liability, Transaction, FamilyMember, Notification } from '../types';
import { supabase } from '../lib/supabase';

interface FinanceContextType {
  state: FinancialState;
  filteredState: FinancialState;
  isAuthenticated: boolean;
  activeMemberIds: string[];
  isCloudSyncing: boolean;
  setActiveMemberIds: (ids: string[]) => void;
  setAuthenticated: (value: boolean) => void;
  updateProfile: (profile: UserProfile) => void;
  addFamilyMember: (member: FamilyMember) => Promise<{ success: boolean; syncedCount: number; error?: string }>;
  removeFamilyMember: (id: string) => void;
  toggleFamilyMemberTxPermission: (id: string) => void;
  addBank: (bank: BankAccount) => void;
  updateBank: (bank: BankAccount) => void;
  deleteBank: (id: string) => void;
  addCard: (card: CreditCard) => void;
  updateCard: (card: CreditCard) => void;
  deleteCard: (id: string) => void;
  addWallet: (wallet: Wallet) => void;
  updateWallet: (wallet: Wallet) => void;
  deleteWallet: (id: string) => void;
  addIncome: (income: IncomeStream) => void;
  addExpense: (expense: Expense) => void;
  addAsset: (asset: Asset) => void;
  addLiability: (liability: Liability) => void;
  addTransaction: (transaction: Transaction) => void;
  updateTransaction: (transaction: Transaction) => void;
  deleteTransaction: (id: string) => void;
  addTransactionNature: (nature: string) => void;
  deleteTransactionNature: (nature: string) => void;
  clearNotifications: () => void;
  markNotificationRead: (id: string) => void;
  simulateSync: () => Promise<void>;
  resetBoarding: () => Promise<void>;
  loadStateFromCloud: (mobile: string) => Promise<boolean>;
  importState: (newState: FinancialState) => void;
}

const GLOBAL_SESSION_KEY = 'myfin_active_session';
const STATE_PREFIX = 'myfin_state_';

const initialState: FinancialState = {
  profile: { 
    name: '', 
    designation: '', 
    age: 0, 
    city: '', 
    country: 'India', 
    currency: 'INR', 
    mobileNumber: '',
    isBoarded: false, 
    familyMembers: [],
    cloudDatabaseName: 'Default_Vault'
  },
  banks: [],
  cards: [],
  wallets: [], 
  incomes: [],
  expenses: [],
  assets: [],
  liabilities: [],
  transactions: [],
  notifications: [],
  transactionNatures: ['Salary', 'Grocery', 'Rent', 'Investment', 'Loan Repayment', 'Medical', 'Dining', 'Travel', 'Utilities'],
  capital: 0
};

const FinanceContext = createContext<FinanceContextType | undefined>(undefined);

export const useFinance = () => {
  const context = useContext(FinanceContext);
  if (!context) throw new Error('useFinance must be used within a FinanceProvider');
  return context;
};

export const FinanceProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [isAuthenticated, setAuthenticated] = useState(false);
  const [activeMemberIds, setActiveMemberIds] = useState<string[]>([]);
  const [isCloudSyncing, setIsCloudSyncing] = useState(false);
  const [activeMobile, setActiveMobile] = useState<string | null>(() => localStorage.getItem(GLOBAL_SESSION_KEY));

  const [state, setState] = useState<FinancialState>(() => {
    const mobile = localStorage.getItem(GLOBAL_SESSION_KEY);
    if (mobile) {
      const saved = localStorage.getItem(`${STATE_PREFIX}${mobile}`);
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...initialState, ...parsed };
        } catch (e) {
          return initialState;
        }
      }
    }
    return initialState;
  });

  useEffect(() => {
    if (state.profile.mobileNumber && state.profile.isBoarded) {
      localStorage.setItem(GLOBAL_SESSION_KEY, state.profile.mobileNumber);
      localStorage.setItem(`${STATE_PREFIX}${state.profile.mobileNumber}`, JSON.stringify(state));
    }
  }, [state]);

  useEffect(() => {
    const persistToSupabase = async () => {
      if (!state.profile.mobileNumber || !state.profile.isBoarded) return;

      setIsCloudSyncing(true);
      try {
        const { error } = await supabase
          .from('user_states')
          .upsert({ 
            mobile_number: state.profile.mobileNumber, 
            state: state,
            updated_at: new Date().toISOString()
          }, { onConflict: 'mobile_number' });

        if (error) console.error('Supabase Persist Error:', error);
      } catch (err) {
        console.error('Cloud sync failed:', err);
      } finally {
        setTimeout(() => setIsCloudSyncing(false), 500);
      }
    };

    const timeoutId = setTimeout(persistToSupabase, 2000);
    return () => clearTimeout(timeoutId);
  }, [state]);

  const applyTransactionEffect = (transaction: Transaction, newState: FinancialState, isReversing: boolean) => {
    const factor = isReversing ? -1 : 1;
    const totalAmount = (transaction.amount || 0) + (transaction.sharedAmount || 0);
    const balanceDelta = (transaction.type === 'Income' || transaction.type === 'Liability') ? totalAmount : -totalAmount;
    const finalBalanceDelta = balanceDelta * factor;

    if (transaction.accountType === 'bank') {
      newState.banks = (newState.banks || []).map(b => b.id === transaction.accountId ? { ...b, balance: b.balance + finalBalanceDelta } : b);
    } else if (transaction.accountType === 'card') {
      const cardDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.cards = (newState.cards || []).map(c => c.id === transaction.accountId ? { ...c, balance: c.balance + cardDelta } : c);
    } else if (transaction.accountType === 'wallet') {
      newState.wallets = (newState.wallets || []).map(w => w.id === transaction.accountId ? { ...w, balance: w.balance + finalBalanceDelta } : w);
    } else if (transaction.accountType === 'liability') {
      const liabilityDelta = (transaction.type === 'Income' || transaction.type === 'Liability' ? -totalAmount : totalAmount) * factor;
      newState.liabilities = (newState.liabilities || []).map(l => l.id === transaction.accountId ? { ...l, amount: l.amount + liabilityDelta } : l);
    }

    if (isReversing) {
      newState.incomes = (newState.incomes || []).filter(i => i.id !== transaction.id);
      newState.expenses = (newState.expenses || []).filter(e => e.id !== transaction.id);
      newState.assets = (newState.assets || []).filter(a => a.id !== transaction.id && !a.id.startsWith(transaction.id + '_shared'));
      newState.liabilities = (newState.liabilities || []).filter(l => l.id !== transaction.id && !l.id.startsWith(transaction.id + '_shared'));
    } else {
      const selfShare = transaction.amount;
      const sharedPortion = transaction.sharedAmount || 0;

      switch (transaction.type) {
        case 'Income':
          if (selfShare > 0) {
            newState.incomes.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: selfShare, periodicity: 'Monthly', dateOfReceipt: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.liabilities.push({ id: transaction.id + '_shared_payable', name: `Payable (Shared ${transaction.nature}): ${transaction.description}`, amount: sharedPortion, type: 'Payable', ownerId: transaction.ownerId });
          }
          break;
        case 'Expense':
          if (selfShare > 0) {
            newState.expenses.push({ id: transaction.id, category: transaction.nature, amount: selfShare, date: transaction.date, ownerId: transaction.ownerId });
          }
          if (sharedPortion > 0) {
            newState.assets.push({ id: transaction.id + '_shared_receivable', name: `Receivable (Shared ${transaction.nature}): ${transaction.description}`, value: sharedPortion, type: 'Receivable', ownerId: transaction.ownerId });
          }
          break;
        case 'Asset':
          newState.assets.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, value: transaction.amount, type: 'Physical', ownerId: transaction.ownerId });
          break;
        case 'Liability':
          newState.liabilities.push({ id: transaction.id, name: `${transaction.nature}: ${transaction.description}`, amount: transaction.amount, type: 'Debt', ownerId: transaction.ownerId });
          break;
      }
    }
  };

  const addTransactionNature = (nature: string) => {
    setState(prev => {
      if (prev.transactionNatures.includes(nature)) return prev;
      return { ...prev, transactionNatures: [...prev.transactionNatures, nature] };
    });
  };

  const deleteTransactionNature = (nature: string) => {
    setState(prev => ({
      ...prev,
      transactionNatures: prev.transactionNatures.filter(n => n !== nature)
    }));
  };

  const loadStateFromCloud = async (mobile: string): Promise<boolean> => {
    try {
      const { data, error } = await supabase.from('user_states').select('state').eq('mobile_number', mobile).single();
      if (data && data.state) {
        setState({ ...initialState, ...data.state });
        setActiveMobile(mobile);
        localStorage.setItem(GLOBAL_SESSION_KEY, mobile);
        setAuthenticated(true);
        return true;
      }
      return false;
    } catch (err) {
      return false;
    }
  };

  const importState = (newState: FinancialState) => {
    if (newState && newState.profile && newState.profile.mobileNumber) {
      setState({ ...initialState, ...newState });
      setActiveMobile(newState.profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, newState.profile.mobileNumber);
      setAuthenticated(true);
    }
  };

  const updateProfile = (profile: UserProfile) => {
    setState(prev => ({ ...prev, profile: { ...profile, isBoarded: true } }));
    if (profile.mobileNumber) {
      setActiveMobile(profile.mobileNumber);
      localStorage.setItem(GLOBAL_SESSION_KEY, profile.mobileNumber);
    }
  };

  const addFamilyMember = async (member: FamilyMember): Promise<{ success: boolean; syncedCount: number; error?: string }> => {
    if (member.mobileNumber === state.profile.mobileNumber) return { success: false, syncedCount: 0, error: "Cannot link your own account." };
    if (state.profile.familyMembers.some(m => m.mobileNumber === member.mobileNumber)) return { success: false, syncedCount: 0, error: 'Member already linked.' };
    let syncedCount = 0;
    let memberData: any = null;
    try {
      const { data } = await supabase.from('user_states').select('state').eq('mobile_number', member.mobileNumber).single();
      if (data && data.state) memberData = data.state;
    } catch (err) {}
    setState(prev => {
      const newFamilyMembers = [...(prev.profile.familyMembers || []), { ...member, canAddTransactions: member.canAddTransactions ?? true }];
      if (!memberData) return { ...prev, profile: { ...prev.profile, familyMembers: newFamilyMembers } };
      const syncTag = (item: any) => ({ ...item, id: `${member.id}_${item.id}`, ownerId: member.id });
      const newBanks = (memberData.banks || []).map(syncTag);
      const newCards = (memberData.cards || []).map(syncTag);
      const newWallets = (memberData.wallets || []).map(syncTag);
      const newTransactions = (memberData.transactions || []).map(syncTag);
      const newIncomes = (memberData.incomes || []).map(syncTag);
      const newExpenses = (memberData.expenses || []).map(syncTag);
      const newAssets = (memberData.assets || []).map(syncTag);
      const newLiabilities = (memberData.liabilities || []).map(syncTag);
      syncedCount = newBanks.length + newCards.length + newWallets.length + newTransactions.length;
      return {
        ...prev,
        profile: { ...prev.profile, familyMembers: newFamilyMembers },
        banks: [...(prev.banks || []), ...newBanks],
        cards: [...(prev.cards || []), ...newCards],
        wallets: [...(prev.wallets || []), ...newWallets],
        transactions: [...(prev.transactions || []), ...newTransactions],
        incomes: [...(prev.incomes || []), ...newIncomes],
        expenses: [...(prev.expenses || []), ...newExpenses],
        assets: [...(prev.assets || []), ...newAssets],
        liabilities: [...(prev.liabilities || []), ...newLiabilities],
        capital: prev.capital + (memberData.capital || 0),
        notifications: [...(prev.notifications || []), {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Family Sync Complete',
          message: `Linked ${member.name} and synced ${syncedCount} records.`,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          type: 'sync',
          isRead: false
        }]
      };
    });
    return { success: true, syncedCount };
  };

  const removeFamilyMember = (id: string) => setState(prev => ({
    ...prev,
    profile: { ...prev.profile, familyMembers: (prev.profile.familyMembers || []).filter(m => m.id !== id) }
  }));

  const toggleFamilyMemberTxPermission = (id: string) => setState(prev => ({
    ...prev,
    profile: {
      ...prev.profile,
      familyMembers: prev.profile.familyMembers.map(m => m.id === id ? { ...m, canAddTransactions: !m.canAddTransactions } : m)
    }
  }));

  const addBank = (bank: BankAccount) => setState(prev => ({ 
    ...prev, 
    banks: [...(prev.banks || []), bank],
    capital: prev.capital + bank.balance 
  }));
  const updateBank = (bank: BankAccount) => setState(prev => {
    const old = prev.banks.find(b => b.id === bank.id);
    const diff = bank.balance - (old?.balance || 0);
    return { 
      ...prev, 
      banks: prev.banks.map(b => b.id === bank.id ? bank : b),
      capital: prev.capital + diff
    };
  });
  const deleteBank = (id: string) => setState(prev => {
    const old = prev.banks.find(b => b.id === id);
    return { 
      ...prev, 
      banks: prev.banks.filter(b => b.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addCard = (card: CreditCard) => setState(prev => {
    // If balance is > 0, it's a liability (decreases capital)
    // If balance is < 0, it's a receivable (increases capital)
    return { 
      ...prev, 
      cards: [...(prev.cards || []), card],
      capital: prev.capital - card.balance
    };
  });
  const updateCard = (card: CreditCard) => setState(prev => {
    const old = prev.cards.find(c => c.id === card.id);
    const oldBal = old?.balance || 0;
    const diff = card.balance - oldBal;
    return { 
      ...prev, 
      cards: prev.cards.map(c => c.id === card.id ? card : c),
      capital: prev.capital - diff
    };
  });
  const deleteCard = (id: string) => setState(prev => {
    const old = prev.cards.find(c => c.id === id);
    return { 
      ...prev, 
      cards: prev.cards.filter(c => c.id !== id),
      capital: prev.capital + (old?.balance || 0)
    };
  });

  const addWallet = (wallet: Wallet) => setState(prev => ({ 
    ...prev, 
    wallets: [...(prev.wallets || []), wallet],
    capital: prev.capital + wallet.balance
  }));
  const updateWallet = (wallet: Wallet) => setState(prev => {
    const old = prev.wallets.find(w => w.id === wallet.id);
    const diff = wallet.balance - (old?.balance || 0);
    return { 
      ...prev, 
      wallets: prev.wallets.map(w => w.id === wallet.id ? wallet : w),
      capital: prev.capital + diff
    };
  });
  const deleteWallet = (id: string) => setState(prev => {
    const old = prev.wallets.find(w => w.id === id);
    return { 
      ...prev, 
      wallets: prev.wallets.filter(w => w.id !== id),
      capital: prev.capital - (old?.balance || 0)
    };
  });

  const addIncome = (income: IncomeStream) => setState(prev => ({ ...prev, incomes: [...prev.incomes, income] }));
  const addExpense = (expense: Expense) => setState(prev => ({ ...prev, expenses: [...prev.expenses, expense] }));

  const addAsset = (asset: Asset) => setState(prev => ({ 
    ...prev, 
    assets: [...prev.assets, asset],
    capital: prev.capital + asset.value
  }));
  const addLiability = (liability: Liability) => setState(prev => ({ 
    ...prev, 
    liabilities: [...prev.liabilities, liability],
    capital: prev.capital - liability.amount
  }));

  const addTransaction = (transaction: Transaction) => {
    setState(prev => {
      const newState = { ...prev, transactions: [transaction, ...(prev.transactions || [])] };
      applyTransactionEffect(transaction, newState, false);
      return newState;
    });
  };

  const updateTransaction = (updatedTransaction: Transaction) => {
    setState(prev => {
      const oldTransaction = (prev.transactions || []).find(t => t.id === updatedTransaction.id);
      if (!oldTransaction) return prev;
      let newState = { ...prev };
      applyTransactionEffect(oldTransaction, newState, true);
      newState.transactions = (newState.transactions || []).map(t => t.id === updatedTransaction.id ? updatedTransaction : t);
      applyTransactionEffect(updatedTransaction, newState, false);
      return newState;
    });
  };

  const deleteTransaction = (id: string) => {
    setState(prev => {
      const transaction = (prev.transactions || []).find(t => t.id === id);
      if (!transaction) return prev;
      const newState = { ...prev, transactions: (prev.transactions || []).filter(t => t.id !== id) };
      applyTransactionEffect(transaction, newState, true);
      return newState;
    });
  };

  const clearNotifications = () => setState(prev => ({ ...prev, notifications: [] }));
  const markNotificationRead = (id: string) => setState(prev => ({
    ...prev,
    notifications: (prev.notifications || []).map(n => n.id === id ? { ...n, isRead: true } : n)
  }));

  const simulateSync = async () => {
    setState(prev => ({
      ...prev,
      notifications: [...(prev.notifications || []), {
        id: Math.random().toString(36).substr(2, 9),
        title: 'Cloud Sync Complete',
        message: 'Your ledger has been successfully synchronized with the cloud vault.',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        type: 'sync',
        isRead: false
      }]
    }));
  };

  const filteredState = useMemo(() => {
    if (activeMemberIds.includes('all')) return state;
    const isFiltered = activeMemberIds.length > 0;
    const filterIds = isFiltered ? activeMemberIds : [undefined, ''];
    const filterFn = (item: any) => filterIds.includes(item.ownerId || '');
    return {
      ...state,
      banks: (state.banks || []).filter(filterFn),
      cards: (state.cards || []).filter(filterFn),
      wallets: (state.wallets || []).filter(filterFn),
      incomes: (state.incomes || []).filter(filterFn),
      expenses: (state.expenses || []).filter(filterFn),
      assets: (state.assets || []).filter(filterFn),
      liabilities: (state.liabilities || []).filter(filterFn),
      transactions: (state.transactions || []).filter(filterFn),
    };
  }, [state, activeMemberIds]);

  const resetBoarding = async () => { 
    const mobile = state.profile.mobileNumber;
    if (mobile) {
      try {
        await supabase.from('user_states').delete().eq('mobile_number', mobile);
        localStorage.removeItem(`${STATE_PREFIX}${mobile}`);
      } catch (err) {
        console.error('Failed to purge cloud record during reset:', err);
      }
    }

    localStorage.removeItem(GLOBAL_SESSION_KEY);
    setState(initialState); 
    setAuthenticated(false); 
    setActiveMobile(null);
  };

  return (
    <FinanceContext.Provider value={{ 
      state, filteredState, isAuthenticated, activeMemberIds, isCloudSyncing, setActiveMemberIds, setAuthenticated, updateProfile, 
      addFamilyMember, removeFamilyMember, toggleFamilyMemberTxPermission,
      addBank, updateBank, deleteBank, addCard, updateCard, deleteCard, addWallet, updateWallet, deleteWallet, addIncome, addExpense, addAsset, addLiability,
      addTransaction, updateTransaction, deleteTransaction, addTransactionNature, deleteTransactionNature,
      clearNotifications, markNotificationRead, simulateSync, resetBoarding, loadStateFromCloud, importState
    }}>
      {children}
    </FinanceContext.Provider>
  );
};

import React, { useState, useMemo } from 'react';
