          <div className="space-y-6">
            <div className="flex justify-between items-center border-b border-slate-100 pb-2">
              <h4 className="text-[9px] md:text-xs font-black text-slate-400 uppercase tracking-widest">Outflow</h4>
              <p className="text-base md:text-lg font-black text-rose-500">{formatCurrency(periodExpense, currency)}</p>
            </div>
            <div className="space-y-1">
              {filteredTransactions.filter(t => t.type === 'Expense').length > 0 ? filteredTransactions.filter(t => t.type === 'Expense').map(t => (
                <div key={t.id} className="flex justify-between items-center py-2 group">
                  <div>
                    <p className="text-xs font-black text-slate-800 uppercase tracking-tight">{t.description}</p>
                    <p className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-0.5">{(t.nature || 'UNSPECIFIED').toUpperCase()}</p>
