export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [scanResult, setScanResult] = useState<{ 
    amount: number; 
    date: string; 
    description: string;
    trades: ExtractedTrade[];
    otherCharges: number;
    pureInvestmentAmount: number;
  } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  // Timer for scanning
  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  // Ensure mandatory natures exist
  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
  }, []);

  // Gemini Parsing Logic
  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsScanning(true);
    setScanTimeLeft(15);
    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: file.type } },
              { text: `Analyze this Zerodha contract note.
              1. Extract 'Trade Date' as "date".
              2. Look at the trades table. Extract rows under 'Security/Contract description' as "scrip".
              3. For each row, look at 'Net Total'. 
                 - If 'Net Total' is in brackets (e.g., '(1,200.00)'), it is a BUY trade (Money Payable). 
                 - Else, it is a SELL trade (Money Receivable).
                 - Return "netTotal" as a positive number.
              4. Extract 'Net amount receivable by Client / (payable by Client)' from the bottom as "finalBottomLine".
                 - If it is in brackets, it is a PAYABLE amount (positive).
                 - Else, it is a RECEIVABLE amount (negative).

              Calculate:
              - "pureInvestmentAmount": Sum of absolute 'Net Total' values for all trades.
              - "otherCharges": Absolute value of ("finalBottomLine" - Sum of individual "netTotal" signed by buy/sell). 
                Specifically: |finalBottomLine| - |pureInvestmentAmount| is NOT always correct. 
                Use: Other Charges = (Total Payable - Total Buy Net Totals) OR (Total Sale Net Totals - Total Receivable).

              Return ONLY a JSON object:
              {
                "date": "YYYY-MM-DD",
                "finalBottomLine": number,
                "pureInvestmentAmount": number,
                "otherCharges": number,
                "trades": [{"scrip": "string", "type": "BUY"|"SELL", "netTotal": number}]
              }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });

        const result = JSON.parse(response.text || '{}');
        if (result.date) {
          setScanResult({
            ...result,
            amount: result.finalBottomLine,
            description: result.trades?.map((t: ExtractedTrade) => `${t.type} ${t.scrip}`).join(', ')
          });
        } else {
          alert("Could not extract trade details. Ensure the document is a valid Zerodha contract note.");
        }
      } catch (err) {
        console.error("AI Parse Error:", err);
        alert("Failed to process document. Please try again with a clearer image or PDF.");
      } finally {
        setIsScanning(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(file);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;

    const defaultAccount = allAccounts.find(a => (a.ownerId || '') === (formData.ownerId || '')) || allAccounts[0];

    // 1. Transaction for pure investment (Investment in stocks)
    // If net totals sum is a 'payable', it's an Asset buy. If 'receivable', it's Income (sale profit).
    const mainTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: scanResult.amount > 0 ? 'Asset' : 'Income',
      amount: Math.abs(scanResult.pureInvestmentAmount),
      nature: 'Investment in stocks',
      description: `Zerodha Trade: ${scanResult.description}`,
      accountId: defaultAccount?.id || '',
      accountType: defaultAccount?.type || 'bank',
      date: scanResult.date,
      ownerId: formData.ownerId
    };

    // 2. Transaction for Other Charges (Expense)
    if (scanResult.otherCharges > 0) {
      const chargesTx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Zerodha Brokerage & Taxes for trades on ${scanResult.date}`,
        accountId: defaultAccount?.id || '',
        accountType: defaultAccount?.type || 'bank',
        date: scanResult.date,
        ownerId: formData.ownerId
      };
      addTransaction(chargesTx);
    }

    addTransaction(mainTx);
    setScanResult(null);
  };

  useEffect(() => {
    if (!formData.nature && natures.length > 0) {
      setFormData(prev => ({ ...prev, nature: natures[0] }));
    }
  }, [natures]);

  useEffect(() => {
    if (!formData.isShared) return;
    const total = Math.max(1, formData.numberOfPeople);
    const externalCount = formData.includeSelf ? total - 1 : total;
    const newList: Participant[] = [];
    if (formData.includeSelf) {
      const ownerName = formData.ownerId ? (familyMembers.find(m => m.id === formData.ownerId)?.name || 'Member') : 'Me';
      newList.push({
        id: 'self',
        name: ownerName,
        mobile: formData.ownerId ? (familyMembers.find(m => m.id === formData.ownerId)?.mobileNumber || '') : (state.profile.mobileNumber || ''),
        value: formData.participants.find(p => p.id === 'self')?.value || '1',
        result: 0,
        isSelf: true
      });
    }
    for (let i = 0; i < externalCount; i++) {
      const existing = formData.participants.filter(p => !p.isSelf)[i];
      newList.push({
        id: existing?.id || Math.random().toString(36).substr(2, 9),
        name: existing?.name || '',
        mobile: existing?.mobile || '',
        value: existing?.value || '1',
        result: 0,
        isSelf: false
      });
    }
    setFormData(prev => ({ ...prev, participants: newList }));
  }, [formData.isShared, formData.numberOfPeople, formData.includeSelf, formData.ownerId]);

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = [];
    const ownersWithCash = new Set();
    (state.wallets || []).forEach(w => {
      const ownerKey = w.ownerId || '';
      if (w.name === 'Cash') {
        if (!ownersWithCash.has(ownerKey)) {
          wallets.push({ id: w.id, name: 'Cash', type: 'wallet' as const, ownerId: w.ownerId });
          ownersWithCash.add(ownerKey);
        }
      } else {
        wallets.push({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId });
      }
    });
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const participantsWithResults = useMemo(() => {
    const totalAmount = Number(formData.amount) || 0;
    if (totalAmount <= 0 || formData.participants.length === 0) return formData.participants;
    const parts = [...formData.participants];
    if (formData.splitType === 'equal') {
      const share = totalAmount / parts.length;
      return parts.map(p => ({ ...p, result: share }));
    }
    if (formData.splitType === 'exact') return parts.map(p => ({ ...p, result: Number(p.value) || 0 }));
    if (formData.splitType === 'percentage') return parts.map(p => ({ ...p, result: (Number(p.value) || 0) / 100 * totalAmount }));
    if (formData.splitType === 'shares') {
      const totalShares = parts.reduce((acc, p) => acc + (Number(p.value) || 0), 0);
      if (totalShares === 0) return parts.map(p => ({ ...p, result: 0 }));
      return parts.map(p => ({ ...p, result: (Number(p.value) / totalShares) * totalAmount }));
    }
    return parts;
  }, [formData.amount, formData.participants, formData.splitType]);

  const splitValidation = useMemo(() => {
    const totalAmount = Number(formData.amount) || 0;
    if (totalAmount <= 0) return { isValid: true, diff: 0 };
    const currentSum = participantsWithResults.reduce((acc, p) => acc + p.result, 0);
    const diff = totalAmount - currentSum;
    if (formData.splitType === 'exact' || formData.splitType === 'percentage') return { isValid: Math.abs(diff) < 0.01, diff };
    return { isValid: true, diff: 0 };
  }, [formData.amount, formData.splitType, participantsWithResults]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const totalValue = t.amount + (t.sharedAmount || 0);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(totalValue),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numberOfPeople: t.numberOfPeople || 2,
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) { alert("Nature of Transaction is mandatory."); return; }
    if (!splitValidation.isValid) { alert(`Variance error: ${formatCurrency(splitValidation.diff, currency)}`); return; }
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source account required."); return; }

    let userShare = 0;
    let sharedAmount = 0;
    let sharedContacts: SharedContact[] = [];
    if (formData.isShared) {
      const selfParticipant = participantsWithResults.find(p => p.isSelf);
      userShare = selfParticipant ? selfParticipant.result : 0;
      const otherParticipants = participantsWithResults.filter(p => !p.isSelf);
      sharedAmount = otherParticipants.reduce((acc, p) => acc + p.result, 0);
      sharedContacts = otherParticipants.map(p => ({ name: p.name || 'External', mobile: p.mobile || '?', amount: p.result }));
    } else {
      userShare = Number(formData.amount);
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: userShare,
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.numberOfPeople,
      sharedAmount: sharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined,
      ownerId: formData.ownerId
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const updateParticipant = (id: string, field: keyof Participant, val: string) => {
    setFormData(prev => ({ ...prev, participants: prev.participants.map(p => p.id === id ? { ...p, [field]: val } : p) }));
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 md:gap-6">
        <div><h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight uppercase">Ledger Hub</h3><p className="text-[9px] md:text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Dual Entry Reconciliation</p></div>
        <div className="grid grid-cols-2 md:flex md:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-3 md:px-6 py-2.5 md:py-3 bg-indigo-900 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-950 transition-all shadow-lg"
          >
            <span>📄</span> Zerodha Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-3 md:px-6 py-2.5 md:py-3 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-3 md:px-6 py-2.5 md:py-3 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-3 md:px-6 py-2.5 md:py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-3 md:px-6 py-2.5 md:py-3 bg-indigo-600 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Debt</button>
        </div>
      </div>

      {/* Scanning UI */}
      {isScanning && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/90 backdrop-blur-md">
          <div className="text-center space-y-6">
            <div className="w-24 h-24 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mx-auto relative flex items-center justify-center">
              <span className="text-white font-black text-lg">{scanTimeLeft}s</span>
            </div>
            <div className="space-y-2">
              <h4 className="text-xl font-black text-white uppercase tracking-tighter">AI Analysis in Progress</h4>
              <p className="text-indigo-300 text-[10px] font-black uppercase tracking-widest animate-pulse">Scanning trades... Est. {scanTimeLeft}s left</p>
              <p className="text-slate-500 text-[8px] font-bold uppercase tracking-widest max-w-[240px] mx-auto opacity-70">Gemini is extracting scrip details and separating 'Other Charges' from base investment.</p>
            </div>
          </div>
        </div>
      )}

      {/* Scan Confirmation */}
      {scanResult && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/80 backdrop-blur-xl p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 my-8">
            <div className="text-center mb-8">
              <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-2xl flex items-center justify-center text-3xl mx-auto mb-4">📈</div>
              <h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter">Ledger Verification</h3>
              <p className="text-[9px] font-black text-slate-400 uppercase mt-1">Zerodha Contract Note • {scanResult.date}</p>
            </div>

            <div className="space-y-6 mb-8">
              <div className="p-5 bg-slate-900 text-white rounded-2xl border border-slate-800 shadow-xl">
                <p className="text-[8px] font-black text-slate-500 uppercase mb-1 tracking-widest">Net Outflow/Inflow</p>
                <p className="text-3xl font-black tracking-tight">{formatCurrency(Math.abs(scanResult.amount), currency)}</p>
              </div>

              <div className="grid grid-cols-2 gap-3">
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <p className="text-[8px] font-black text-slate-400 uppercase mb-1">Stock Movement</p>
                  <p className="text-[11px] font-black text-slate-800 uppercase">{formatCurrency(scanResult.pureInvestmentAmount, currency)}</p>
                </div>
                <div className="p-4 bg-slate-50 rounded-2xl border border-slate-100">
                  <p className="text-[8px] font-black text-slate-400 uppercase mb-1">Other Charges</p>
                  <p className="text-[11px] font-black text-rose-500 uppercase">{formatCurrency(scanResult.otherCharges, currency)}</p>
                </div>
              </div>

              <div className="p-5 bg-slate-50 rounded-2xl border border-slate-100">
                <p className="text-[8px] font-black text-slate-400 uppercase mb-3 tracking-widest border-b border-slate-200 pb-2">Scrip Mapping (Security/Contract)</p>
                <div className="space-y-3 max-h-[160px] overflow-y-auto custom-scrollbar pr-2">
                  {scanResult.trades?.map((t, i) => (
                    <div key={i} className="flex justify-between items-center text-[10px]">
                      <div className="flex items-center gap-2">
                        <span className={`px-1.5 py-0.5 rounded-[4px] font-black ${t.type === 'BUY' ? 'bg-indigo-100 text-indigo-600' : 'bg-emerald-100 text-emerald-600'}`}>{t.type}</span>
                        <span className="font-black text-slate-800 uppercase">{t.scrip}</span>
                      </div>
                      <span className="font-black text-slate-800">{formatCurrency(t.netTotal, currency)}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            <div className="flex flex-col gap-3">
              <button onClick={commitScannedTrade} className="w-full py-5 bg-indigo-600 text-white font-black text-xs uppercase rounded-2xl shadow-xl active:scale-95 transition-all">Commit Dual-Entry Update</button>
              <button onClick={() => setScanResult(null)} className="w-full py-4 text-slate-400 font-black text-[10px] uppercase">Discard Scan</button>
            </div>
          </div>
        </div>
      )}

      {/* Desktop Table */}
      <div className="hidden md:block bg-white rounded-[2rem] border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 text-slate-500 text-[9px] font-black uppercase tracking-[0.3em] border-b border-slate-200">
              <tr>
                <th className="px-8 py-7">Timeline</th>
                <th className="px-8 py-7">Classification & Nature</th>
                <th className="px-8 py-7">Execution</th>
                <th className="px-8 py-7 text-right">User Share</th>
                <th className="px-8 py-7 text-center">Protocol</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {transactionList.map(t => (
                <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-8 py-6 text-[11px] font-black text-slate-400 uppercase">{t.date}</td>
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-2">
                      <p className="text-sm font-black text-slate-800 tracking-tight">{t.description}</p>
                      {t.isShared && <span className="bg-indigo-600 text-white text-[7px] font-black px-1.5 py-0.5 rounded-sm uppercase tracking-widest">SPLIT</span>}
                    </div>
                    <span className="text-[8px] text-indigo-600 font-black uppercase tracking-widest mt-1.5 inline-block bg-indigo-50 px-2 py-0.5 rounded">{t.nature}</span>
                  </td>
                  <td className="px-8 py-6"><span className="text-[9px] font-black text-slate-500 bg-slate-100 px-3 py-1.5 rounded-lg uppercase">{getOwnerName(t.ownerId)}</span></td>
                  <td className="px-8 py-6 text-right">
                    <div className={`text-base font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>{t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}</div>
                    {t.isShared && <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest mt-1">Flow: {formatCurrency(t.amount + (t.sharedAmount || 0), currency)}</div>}
                  </td>
                  <td className="px-8 py-6 text-center">
                    <div className="flex items-center justify-center gap-3 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => handleEditClick(t)} className="p-2 text-slate-300 hover:text-indigo-600 text-lg">✎</button>
                      <button onClick={() => setConfirmDeleteTx(t)} className="p-2 text-slate-300 hover:text-rose-500 text-lg">✕</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Mobile Card List */}
      <div className="md:hidden space-y-4">
        {transactionList.map(t => (
          <div key={t.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm relative active:bg-slate-50 transition-colors">
            <div className="flex justify-between items-start mb-3">
               <div>
                  <div className="flex items-center gap-2">
                     <p className="text-sm font-black text-slate-800">{t.description}</p>
                     {t.isShared && <span className="bg-indigo-600 text-white text-[6px] font-black px-1.5 py-0.5 rounded-sm uppercase tracking-widest">SPLIT</span>}
                  </div>
                  <div className="flex items-center gap-2 mt-1">
                     <span className="text-[8px] text-slate-400 font-black uppercase tracking-widest">{t.date}</span>
                     <span className="text-[7px] text-indigo-600 font-black uppercase tracking-widest bg-indigo-50 px-1.5 py-0.5 rounded">{t.nature}</span>
                  </div>
               </div>
               <div className="text-right">
                  <p className={`text-sm font-black ${t.type === 'Income' || t.type === 'Liability' ? 'text-emerald-600' : (t.type === 'Expense' ? 'text-rose-500' : 'text-slate-800')}`}>
                    {t.type === 'Income' || t.type === 'Liability' ? '↑' : '↓'} {formatCurrency(t.amount, currency)}
                  </p>
                  <p className="text-[8px] font-black text-slate-400 uppercase tracking-widest mt-1">{getOwnerName(t.ownerId)}</p>
               </div>
            </div>
            <div className="flex gap-4 pt-3 border-t border-slate-50">
               <button onClick={() => handleEditClick(t)} className="text-[9px] font-black text-indigo-600 uppercase tracking-widest">Edit Entry</button>
               <button onClick={() => setConfirmDeleteTx(t)} className="text-[9px] font-black text-rose-400 uppercase tracking-widest">Purge</button>
            </div>
          </div>
        ))}
        {transactionList.length === 0 && (
          <div className="py-20 text-center text-slate-300 italic text-xs">No ledger entries found</div>
        )}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-50 flex justify-center items-start bg-slate-900/60 backdrop-blur-xl p-3 md:p-4 overflow-y-auto pt-6 md:pt-10 pb-20">
          <div className="bg-white w-full max-w-2xl rounded-[2rem] md:rounded-[3rem] p-6 md:p-12 border border-slate-200 shadow-2xl animate-in zoom-in-95 duration-200 relative mb-10">
            <div className="flex justify-between items-center mb-8 md:mb-12 border-b border-slate-100 pb-4 md:pb-8">
              <div><h3 className="text-xl md:text-3xl font-black text-slate-800 tracking-tighter uppercase">{formData.type} Record</h3><p className="text-[8px] md:text-[10px] text-slate-400 font-black uppercase tracking-widest mt-2">Protocol v3.0</p></div>
              <button onClick={() => setShowModal(false)} className="text-slate-200 hover:text-slate-800 font-black p-2 md:p-4 text-xl md:text-2xl">✕</button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6 md:space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Entity</label>
                  <select className="w-full p-4 md:p-5 bg-slate-50 border border-slate-200 rounded-2xl md:rounded-3xl outline-none font-black text-xs md:text-sm" value={formData.ownerId} onChange={e => setFormData({ ...formData, ownerId: e.target.value, accountId: '' })}>
                    <option value="">Me (Primary)</option>{familyMembers.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Nature</label>
                  <select required className="w-full p-4 md:p-5 bg-slate-50 border border-slate-200 rounded-2xl md:rounded-3xl outline-none font-black text-xs md:text-sm" value={formData.nature} onChange={e => setFormData({ ...formData, nature: e.target.value })}>
                    <option value="" disabled>Select Protocol</option>
                    {natures.map(n => <option key={n} value={n}>{(n || '').toUpperCase()}</option>)}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Total Value ({currency})</label>
                  <input required type="number" step="any" className="w-full p-4 md:p-6 bg-slate-50 border border-slate-200 rounded-[1.5rem] md:rounded-[2rem] outline-none font-black text-2xl md:text-4xl" value={formData.amount} onChange={e => setFormData({ ...formData, amount: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Timeline</label>
                  <input required type="date" className="w-full p-4 md:p-6 bg-slate-50 border border-slate-200 rounded-[1.5rem] md:rounded-[2rem] outline-none font-black text-xs md:text-sm uppercase" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-10">
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Description</label>
                  <input required className="w-full p-4 md:p-6 bg-slate-50 border border-slate-200 rounded-[1.5rem] md:rounded-[2rem] outline-none font-bold text-xs md:text-sm" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] md:text-[10px] font-black text-slate-400 uppercase tracking-widest block ml-2">Instrument</label>
                  <select required className="w-full p-4 md:p-5 bg-slate-50 border border-slate-200 rounded-2xl md:rounded-3xl outline-none font-black text-xs md:text-sm" value={formData.accountId} onChange={e => setFormData({ ...formData, accountId: e.target.value })}>
                    <option value="">Select Account</option>
                    {allAccounts.filter(a => (a.ownerId || '') === (formData.ownerId || '')).map(acc => (<option key={acc.id} value={acc.id}>{acc.name} ({(acc.type || '').toUpperCase()})</option>))}
                  </select>
                </div>
              </div>

              {/* SHARED SPLIT ENGINE */}
              <div className="bg-slate-900 rounded-[2rem] md:rounded-[2.5rem] p-6 md:p-10 space-y-6 md:space-y-10 text-white border border-slate-800">
                <div className="flex items-center justify-between border-b border-slate-800 pb-6">
                  <div className="flex items-center gap-3 md:gap-4"><div className="w-10 h-10 md:w-14 md:h-14 bg-indigo-600 rounded-xl md:rounded-2xl flex items-center justify-center text-xl md:text-2xl">🤝</div><div><h4 className="text-xs md:text-base font-black uppercase tracking-widest">Split Engine</h4><p className="text-[7px] md:text-[9px] text-slate-500 font-bold uppercase tracking-widest mt-1">Dual Entry Protocol</p></div></div>
                  <button type="button" onClick={() => setFormData(prev => ({ ...prev, isShared: !prev.isShared }))} className={`relative inline-flex h-8 w-16 md:h-10 md:w-20 items-center rounded-full transition-all ${formData.isShared ? 'bg-indigo-600' : 'bg-slate-700'}`}><span className={`inline-block h-6 w-6 md:h-8 md:w-8 transform bg-white rounded-full transition-transform ${formData.isShared ? 'translate-x-9 md:translate-x-11' : 'translate-x-1'}`} /></button>
                </div>
                {formData.isShared && (
                  <div className="space-y-6 md:space-y-10 animate-in slide-in-from-top-4">
                    <div className="grid grid-cols-2 gap-4 md:gap-8 bg-slate-800/50 p-4 md:p-8 rounded-[1.5rem] md:rounded-[2rem] border border-slate-700/50">
                      <div className="space-y-2"><label className="text-[8px] md:text-[10px] font-black text-slate-500 uppercase tracking-widest">Participants</label><input type="number" min={1} className="w-full p-3 md:p-4 bg-slate-900 border border-slate-700 rounded-xl md:rounded-2xl text-white font-black text-xs" value={formData.numberOfPeople} onChange={e => setFormData({ ...formData, numberOfPeople: parseInt(e.target.value) || 1 })} /></div>
                      <div className="space-y-2"><label className="text-[8px] md:text-[10px] font-black text-slate-500 uppercase tracking-widest">Incl. Self?</label><button type="button" onClick={() => setFormData(prev => ({ ...prev, includeSelf: !prev.includeSelf }))} className={`w-full p-3 md:p-4 border rounded-xl md:rounded-2xl text-[8px] md:text-[10px] font-black uppercase ${formData.includeSelf ? 'bg-white text-slate-900' : 'bg-slate-900 text-slate-500'}`}>{formData.includeSelf ? 'Yes' : 'No'}</button></div>
                    </div>
                    <div className="flex flex-wrap gap-1 md:gap-2 bg-slate-800 p-1 md:p-2 rounded-xl md:rounded-2xl">
                      {(['equal', 'exact', 'percentage', 'shares'] as SplitType[]).map(type => (<button key={type} type="button" onClick={() => setFormData({ ...formData, splitType: type })} className={`flex-1 py-2 px-2 rounded-lg text-[7px] md:text-[9px] font-black uppercase tracking-widest transition-all ${formData.splitType === type ? 'bg-indigo-600 text-white shadow-xl' : 'text-slate-500'}`}>{(type || '').toUpperCase()}</button>))}
                    </div>
                    <div className="space-y-3 max-h-[250px] overflow-y-auto custom-scrollbar pr-1">
                      {participantsWithResults.map((p, idx) => (
                        <div key={p.id} className="p-4 bg-slate-800/40 border border-slate-700/40 rounded-2xl space-y-3">
                          <div className="flex items-center justify-between">
                            <div className="flex items-center gap-3"><div className="w-8 h-8 md:w-10 md:h-10 rounded-lg md:rounded-xl bg-slate-700 flex items-center justify-center font-black text-[10px]">{p.isSelf ? 'ME' : idx + 1}</div><div className="flex-1">{p.isSelf ? <p className="text-[10px] font-black text-white">{p.name}</p> : <div className="flex flex-col md:flex-row gap-2 md:gap-4"><input placeholder="Name" className="bg-transparent border-b border-slate-700 text-[10px] text-white outline-none w-full md:w-32" value={p.name} onChange={e => updateParticipant(p.id, 'name', e.target.value)} /></div>}</div></div>
                            <div className="text-right"><p className="text-[11px] font-black text-white">{formatCurrency(p.result, currency)}</p></div>
                          </div>
                          {formData.splitType !== 'equal' && <input type="number" className="w-full p-3 bg-slate-900 border border-slate-700 rounded-xl text-right text-indigo-400 font-black outline-none text-xs" value={p.value} onChange={e => updateParticipant(p.id, 'value', e.target.value)} />}
                        </div>
                      ))}
                    </div>
                    <div className={`p-5 md:p-8 rounded-[1.5rem] md:rounded-[2rem] flex flex-col md:flex-row justify-between md:items-center gap-4 ${splitValidation.isValid ? 'bg-indigo-600 shadow-xl' : 'bg-rose-600/20 border border-rose-500/50'}`}>
                       <div className="space-y-1"><p className="text-[8px] md:text-[10px] font-black uppercase text-indigo-100">{splitValidation.isValid ? 'Valid Configuration' : 'Gap Found'}</p><p className="text-xs font-bold text-white">My Delta: <span className="font-black text-lg md:text-xl">{formatCurrency(participantsWithResults.find(p => p.isSelf)?.result || 0, currency)}</span></p></div>
                       <div className="text-left md:text-right"><p className="text-[8px] md:text-[10px] font-black uppercase text-indigo-100 mb-1 md:mb-2">Total Shared</p><p className="text-2xl md:text-3xl font-black text-white">{formatCurrency(participantsWithResults.filter(p => !p.isSelf).reduce((acc, p) => acc + p.result, 0), currency)}</p></div>
                    </div>
                  </div>
                )}
              </div>

              <div className="flex flex-col md:flex-row gap-3 md:gap-6 pt-2">
                <button type="button" onClick={() => setShowModal(false)} className="order-2 md:order-1 flex-1 py-4 md:py-6 bg-slate-100 text-slate-500 font-black text-[10px] md:text-[11px] uppercase tracking-widest rounded-2xl md:rounded-3xl">Discard</button>
                <button type="submit" className="order-1 md:order-2 flex-[2.5] py-4 md:py-6 bg-indigo-600 text-white rounded-2xl md:rounded-3xl font-black text-xs md:text-sm uppercase tracking-widest shadow-xl">Commit Ledger</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDeleteTx && <DeleteTransactionConfirmationModal transaction={confirmDeleteTx} currency={currency} onCancel={() => setConfirmDeleteTx(null)} onConfirm={() => { deleteTransaction(confirmDeleteTx.id); setConfirmDeleteTx(null); }} />}
    </div>
  );
};

const DeleteTransactionConfirmationModal: React.FC<{ transaction: Transaction, currency: string, onCancel: () => void, onConfirm: () => void }> = ({ transaction, currency, onCancel, onConfirm }) => {
  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-slate-900/80 backdrop-blur-2xl p-4">
       <div className="w-full max-sm p-8 md:p-12 bg-white border border-slate-200 rounded-[2.5rem] md:rounded-[3rem] shadow-2xl animate-in zoom-in duration-300">
          <div className="text-center mb-8"><div className="w-20 h-20 md:w-24 md:h-24 rounded-[1.5rem] md:rounded-[2rem] bg-rose-50 text-rose-500 flex items-center justify-center text-4xl md:text-5xl mx-auto mb-6">🗑️</div><h4 className="text-xl md:text-2xl font-black text-slate-800 uppercase">Void entry?</h4><p className="text-[9px] font-black text-slate-400 mt-3 uppercase">Confirm absolute reversal</p></div>
          <div className="bg-slate-50 rounded-2xl md:rounded-[2rem] p-6 md:p-8 mb-8 border border-slate-100"><p className="text-xs md:text-sm font-black text-slate-800 truncate mb-4">{transaction.description}</p><div className="flex justify-between items-center"><span className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase">Flow Impact</span><span className="text-lg md:text-xl font-black text-slate-800">{formatCurrency(transaction.amount + (transaction.sharedAmount || 0), currency)}</span></div></div>
          <div className="flex flex-col gap-4"><button onClick={onConfirm} className="w-full py-4 md:py-6 bg-rose-600 text-white font-black text-[10px] md:text-xs uppercase rounded-2xl md:rounded-3xl shadow-xl">Purge Entry</button><button onClick={onCancel} className="w-full py-3 text-slate-500 font-black text-[8px] md:text-[9px] uppercase">Abort</button></div>
       </div>
    </div>
  );
};

export default Transactions;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { useFinance } from '../store/FinanceContext';
import { TransactionType, SharedContact, Transaction } from '../types';
import { formatCurrency } from '../utils/formatters';
import { GoogleGenAI } from "@google/genai";

type SplitType = 'equal' | 'exact' | 'percentage' | 'shares';

interface Participant {
  id: string; 
  name: string;
  mobile: string;
  value: string; 
  result: number; 
  isSelf: boolean;
}

interface ExtractedTrade {
  scrip: string;
  type: 'BUY' | 'SELL';
  netTotal: number;
}

const Transactions: React.FC = () => {
  const { filteredState, state, addTransaction, updateTransaction, deleteTransaction, addTransactionNature } = useFinance();
  const familyMembers = state.profile?.familyMembers || [];
  const natures = state.transactionNatures || [];
  const [showModal, setShowModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [confirmDeleteTx, setConfirmDeleteTx] = useState<Transaction | null>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [scanTimeLeft, setScanTimeLeft] = useState(15);
  const [pdfPassword, setPdfPassword] = useState('');
  const [showPasswordInput, setShowPasswordInput] = useState(false);
  const [pendingFile, setPendingFile] = useState<File | null>(null);

  const [scanResult, setScanResult] = useState<{ 
    amount: number; 
    date: string; 
    description: string;
    trades: ExtractedTrade[];
    otherCharges: number;
    pureInvestmentAmount: number;
    isPayable: boolean;
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const currency = state.profile.currency;

  const initialFormState = {
    type: 'Expense' as TransactionType,
    amount: '', 
    nature: natures[0] || '',
    description: '',
    accountId: '',
    date: new Date().toISOString().split('T')[0],
    isShared: false,
    includeSelf: true,
    numberOfPeople: 2,
    splitType: 'equal' as SplitType,
    participants: [] as Participant[],
    ownerId: ''
  };

  const [formData, setFormData] = useState(initialFormState);

  // Timer for scanning
  useEffect(() => {
    let timer: number;
    if (isScanning && scanTimeLeft > 0) {
      timer = window.setInterval(() => {
        setScanTimeLeft(prev => Math.max(0, prev - 1));
      }, 1000);
    }
    return () => clearInterval(timer);
  }, [isScanning, scanTimeLeft]);

  // Ensure required natures exist
  useEffect(() => {
    if (!natures.includes('Investment in stocks')) {
      addTransactionNature('Investment in stocks');
    }
    if (!natures.includes('Other Charges')) {
      addTransactionNature('Other Charges');
    }
  }, []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setPendingFile(file);
    setShowPasswordInput(true);
  };

  const startAIParsing = async () => {
    if (!pendingFile) return;

    setShowPasswordInput(false);
    setIsScanning(true);
    setScanTimeLeft(18);

    const reader = new FileReader();
    reader.onloadend = async () => {
      try {
        const base64Data = (reader.result as string).split(',')[1];
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        // Use Gemini 3 Flash as requested/standard for multimodal
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: {
            parts: [
              { inlineData: { data: base64Data, mimeType: pendingFile.type } },
              { text: `Analyze this Zerodha Contract Note PDF. 
              The PDF might be password protected with a PAN number. The provided password hint is: ${pdfPassword}.

              Follow these specific extraction rules:
              1. Recognize 'Trade Date' from the document and use it as "date".
              2. Identify individual stocks listed under the "Security/Contract description" column. 
              3. For each stock row, find the "Net Total" value.
                 - IMPORTANT: If the "Net Total" value is in brackets (e.g., '(1,250.50)'), classify it as a BUY (Positive balance impact for Investment).
                 - If it is a normal number (no brackets), classify it as a SELL (Negative balance impact/Reduction for Investment).
              4. Identify the 'Net amount receivable by Client / (payable by Client)' at the end of the document.
                 - If bracketed, it's a PAYABLE amount (Money Out).
                 - Else, it's a RECEIVABLE amount (Money In).
              5. Calculate "otherCharges": This is the mathematical difference between the absolute sum of all individual "Net Total" values and the absolute "Net amount receivable/payable by Client". This represents taxes, brokerage, and STT.

              Return ONLY a JSON object:
              {
                "date": "YYYY-MM-DD",
                "isPayable": boolean,
                "finalSettlementAmount": number,
                "pureInvestmentAmount": number,
                "otherCharges": number,
                "trades": [
                  {"scrip": "String from Security description", "type": "BUY" | "SELL", "netTotal": number}
                ]
              }` }
            ]
          },
          config: { responseMimeType: "application/json" }
        });

        const result = JSON.parse(response.text || '{}');
        if (result.date) {
          setScanResult({
            ...result,
            amount: result.finalSettlementAmount,
            description: result.trades?.map((t: ExtractedTrade) => `${t.type} ${t.scrip}`).join(', ')
          });
        } else {
          alert("Could not extract trade details. Ensure the document is a valid Zerodha contract note and the password (if any) is correct.");
        }
      } catch (err) {
        console.error("AI Parse Error:", err);
        alert("Failed to process document. The AI might be unable to read the encrypted file directly. Please ensure it's a standard Zerodha PDF.");
      } finally {
        setIsScanning(false);
        setPdfPassword('');
        setPendingFile(null);
        if (fileInputRef.current) fileInputRef.current.value = '';
      }
    };
    reader.readAsDataURL(pendingFile);
  };

  const commitScannedTrade = () => {
    if (!scanResult) return;

    const defaultAccount = allAccounts.find(a => (a.ownerId || '') === (formData.ownerId || '')) || allAccounts[0];

    // 1. Primary Portfolio Impact (Asset for Buy, Income for Sell)
    const mainTx: Transaction = {
      id: Math.random().toString(36).substr(2, 9),
      type: scanResult.isPayable ? 'Asset' : 'Income', // Buy increases asset, Sell counts as incoming flow
      amount: Math.abs(scanResult.pureInvestmentAmount),
      nature: 'Investment in stocks',
      description: `Zerodha Import: ${scanResult.description}`,
      accountId: defaultAccount?.id || '',
      accountType: defaultAccount?.type || 'bank',
      date: scanResult.date,
      ownerId: formData.ownerId
    };

    // 2. Brokerage/Charges Impact (Expense)
    if (scanResult.otherCharges > 0) {
      const chargesTx: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'Expense',
        amount: scanResult.otherCharges,
        nature: 'Other Charges',
        description: `Zerodha Taxes/Charges for trades on ${scanResult.date}`,
        accountId: defaultAccount?.id || '',
        accountType: defaultAccount?.type || 'bank',
        date: scanResult.date,
        ownerId: formData.ownerId
      };
      addTransaction(chargesTx);
    }

    addTransaction(mainTx);
    setScanResult(null);
  };

  const allAccounts = useMemo(() => {
    const banks = (state.banks || []).map(b => ({ id: b.id, name: b.name, type: 'bank' as const, ownerId: b.ownerId }));
    const cards = (state.cards || []).map(c => ({ id: c.id, name: c.lenderName, type: 'card' as const, ownerId: c.ownerId }));
    const liabilities = (state.liabilities || []).filter(l => l.type === 'Debt').map(l => ({ id: l.id, name: l.name, type: 'liability' as const, ownerId: l.ownerId }));
    const wallets = [];
    const ownersWithCash = new Set();
    (state.wallets || []).forEach(w => {
      const ownerKey = w.ownerId || '';
      if (w.name === 'Cash') {
        if (!ownersWithCash.has(ownerKey)) {
          wallets.push({ id: w.id, name: 'Cash', type: 'wallet' as const, ownerId: w.ownerId });
          ownersWithCash.add(ownerKey);
        }
      } else {
        wallets.push({ id: w.id, name: w.name, type: 'wallet' as const, ownerId: w.ownerId });
      }
    });
    return [...banks, ...cards, ...wallets, ...liabilities];
  }, [state.banks, state.cards, state.wallets, state.liabilities]);

  const participantsWithResults = useMemo(() => {
    const totalAmount = Number(formData.amount) || 0;
    if (totalAmount <= 0 || formData.participants.length === 0) return formData.participants;
    const parts = [...formData.participants];
    if (formData.splitType === 'equal') {
      const share = totalAmount / parts.length;
      return parts.map(p => ({ ...p, result: share }));
    }
    if (formData.splitType === 'exact') return parts.map(p => ({ ...p, result: Number(p.value) || 0 }));
    if (formData.splitType === 'percentage') return parts.map(p => ({ ...p, result: (Number(p.value) || 0) / 100 * totalAmount }));
    if (formData.splitType === 'shares') {
      const totalShares = parts.reduce((acc, p) => acc + (Number(p.value) || 0), 0);
      if (totalShares === 0) return parts.map(p => ({ ...p, result: 0 }));
      return parts.map(p => ({ ...p, result: (Number(p.value) / totalShares) * totalAmount }));
    }
    return parts;
  }, [formData.amount, formData.participants, formData.splitType]);

  const splitValidation = useMemo(() => {
    const totalAmount = Number(formData.amount) || 0;
    if (totalAmount <= 0) return { isValid: true, diff: 0 };
    const currentSum = participantsWithResults.reduce((acc, p) => acc + p.result, 0);
    const diff = totalAmount - currentSum;
    if (formData.splitType === 'exact' || formData.splitType === 'percentage') return { isValid: Math.abs(diff) < 0.01, diff };
    return { isValid: true, diff: 0 };
  }, [formData.amount, formData.splitType, participantsWithResults]);

  const handleOpenModal = (type: TransactionType) => {
    setEditingId(null);
    setFormData({ ...initialFormState, type, nature: natures[0] || '' });
    setShowModal(true);
  };

  const handleEditClick = (t: Transaction) => {
    setEditingId(t.id);
    const totalValue = t.amount + (t.sharedAmount || 0);
    setFormData({
      ...initialFormState,
      type: t.type,
      amount: String(totalValue),
      nature: t.nature,
      description: t.description,
      accountId: t.accountId,
      date: t.date,
      isShared: !!t.isShared,
      includeSelf: t.includeSelf ?? true,
      numberOfPeople: t.numberOfPeople || 2,
      ownerId: t.ownerId || ''
    });
    setShowModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.nature) { alert("Nature of Transaction is mandatory."); return; }
    if (!splitValidation.isValid) { alert(`Variance error: ${formatCurrency(splitValidation.diff, currency)}`); return; }
    const account = allAccounts.find(a => a.id === formData.accountId);
    if (!account) { alert("Source account required."); return; }

    let userShare = 0;
    let sharedAmount = 0;
    let sharedContacts: SharedContact[] = [];
    if (formData.isShared) {
      const selfParticipant = participantsWithResults.find(p => p.isSelf);
      userShare = selfParticipant ? selfParticipant.result : 0;
      const otherParticipants = participantsWithResults.filter(p => !p.isSelf);
      sharedAmount = otherParticipants.reduce((acc, p) => acc + p.result, 0);
      sharedContacts = otherParticipants.map(p => ({ name: p.name || 'External', mobile: p.mobile || '?', amount: p.result }));
    } else {
      userShare = Number(formData.amount);
    }

    const transactionData: Transaction = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      type: formData.type,
      amount: userShare,
      nature: formData.nature,
      description: formData.description,
      accountId: formData.accountId,
      accountType: account.type,
      date: formData.date,
      isShared: formData.isShared,
      includeSelf: formData.includeSelf,
      numberOfPeople: formData.numberOfPeople,
      sharedAmount: sharedAmount,
      sharedContacts: formData.isShared ? sharedContacts : undefined,
      ownerId: formData.ownerId
    };
    if (editingId) updateTransaction(transactionData);
    else addTransaction(transactionData);
    setShowModal(false);
  };

  const updateParticipant = (id: string, field: keyof Participant, val: string) => {
    setFormData(prev => ({ ...prev, participants: prev.participants.map(p => p.id === id ? { ...p, [field]: val } : p) }));
  };

  const getOwnerName = (id?: string) => {
    if (!id) return 'Me';
    const member = familyMembers.find(m => m.id === id);
    return member ? member.name : 'Me';
  };

  const transactionList = filteredState.transactions || [];

  return (
    <div className="space-y-6 md:space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 md:gap-6">
        <div><h3 className="text-lg md:text-xl font-black text-slate-800 tracking-tight uppercase">Ledger Hub</h3><p className="text-[9px] md:text-[10px] text-slate-400 font-black uppercase tracking-widest mt-1">Dual Entry Reconciliation</p></div>
        <div className="grid grid-cols-2 md:flex md:flex-wrap items-center gap-2 md:gap-3">
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*,.pdf" onChange={handleFileUpload} />
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="col-span-2 md:col-span-1 px-3 md:px-6 py-2.5 md:py-3 bg-indigo-900 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-950 transition-all shadow-lg"
          >
            <span>📄</span> Zerodha Import
          </button>
          <button onClick={() => handleOpenModal('Income')} className="px-3 md:px-6 py-2.5 md:py-3 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Income</button>
          <button onClick={() => handleOpenModal('Expense')} className="px-3 md:px-6 py-2.5 md:py-3 bg-rose-50 text-rose-500 border border-rose-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Expense</button>
          <button onClick={() => handleOpenModal('Asset')} className="px-3 md:px-6 py-2.5 md:py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Asset</button>
          <button onClick={() => handleOpenModal('Liability')} className="px-3 md:px-6 py-2.5 md:py-3 bg-indigo-600 text-white rounded-xl md:rounded-2xl text-[9px] md:text-[10px] font-black uppercase tracking-widest">Debt</button>
        </div>
      </div>

      {/* Password Input Modal */}
      {showPasswordInput && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center bg-slate-900/60 backdrop-blur-sm p-4">
          <div className="bg-white w-full max-w-sm rounded-[2rem] p-8 shadow-2xl animate-in zoom-in-95 duration-200">
            <h4 className="text-base font-black text-slate-800 uppercase tracking-tight mb-4">PDF Unlock</h4>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-6 leading-relaxed">Zerodha PDFs are often encrypted. Your PAN (case sensitive) is usually the key.</p>
            <input 
              type="password" 
